1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	    <meta charset="UTF-8">
5	    <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	    <title>All Together Now</title>
7	    <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/@xterm/xterm@5.5.0/css/xterm.min.css">
8	    <style>
9	        * { margin: 0; padding: 0; box-sizing: border-box; }
10	        body { background: #1a1a2e; color: #e0e0e0; font-family: system-ui, sans-serif; height: 100vh; display: flex; flex-direction: column; }
11	        header { padding: 12px 20px; background: #16213e; border-bottom: 1px solid #0f3460; display: flex; align-items: center; gap: 12px; flex-shrink: 0; }
12	        header h1 { font-size: 18px; font-weight: 600; color: #e94560; }
13	        header .agent-count { font-size: 13px; color: #888; }
14	
15	        .dashboard { flex: 1; display: grid; gap: 8px; padding: 8px; min-height: 0; overflow: auto; }
16	        .dashboard.cols-1 { grid-template-columns: 1fr; }
17	        .dashboard.cols-2 { grid-template-columns: 1fr 1fr; }
18	        .dashboard.cols-3 { grid-template-columns: 1fr 1fr 1fr; }
19	        .dashboard.cols-4 { grid-template-columns: 1fr 1fr; grid-template-rows: 1fr 1fr; }
20	
21	        /* Filter bar: text input + chips + group toggle + saved-layouts dropdown.
22	           Sits between the view tabs (in the main header) and the pin row. */
23	        .filter-bar { display: none; gap: 8px; padding: 6px 8px; border-bottom: 1px solid #0f3460; background: #16213e; align-items: center; flex-wrap: wrap; flex-shrink: 0; }
24	        .filter-bar.visible { display: flex; }
25	        .filter-bar input#filter-input { flex: 0 1 240px; padding: 5px 10px; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-size: 12px; outline: none; }
26	        .filter-bar input#filter-input:focus { border-color: #e94560; }
27	        .filter-bar .chip { padding: 3px 10px; font-size: 11px; border: 1px solid #0f3460; background: transparent; color: #888; border-radius: 12px; cursor: pointer; }
28	        .filter-bar .chip:hover { color: #c9d1d9; border-color: #1e3a5f; }
29	        .filter-bar .chip.active { background: #0f3460; color: #4ecca3; border-color: #4ecca3; }
30	        .filter-bar .group-section { display: flex; align-items: center; gap: 4px; }
31	        .filter-bar .group-section label { font-size: 11px; color: #888; }
32	        .filter-bar .group-section select { padding: 3px 6px; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-size: 11px; }
33	        .filter-bar .layouts-section { display: flex; align-items: center; gap: 4px; margin-left: auto; }
34	        .filter-bar .layouts-section select { padding: 3px 6px; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-size: 11px; min-width: 120px; }
35	        .filter-bar .layouts-section button { padding: 3px 10px; background: transparent; border: 1px solid #0f3460; border-radius: 4px; color: #888; cursor: pointer; font-size: 11px; }
36	        .filter-bar .layouts-section button:hover { color: #4ecca3; border-color: #4ecca3; }
37	        .filter-bar .filter-hint { font-size: 10px; color: #6b7280; margin-left: 4px; }
38	        .pin-cell.filtered .pin-name::after { content: ' (filtered)'; color: #6b7280; font-weight: 400; font-style: italic; }
39	
40	        /* Group bands in the treemap — subtle borders around each role
41	           or project cluster. Applied to a positioned overlay rect. */
42	        .group-band { position: absolute; border: 1px dashed #2d3a63; border-radius: 4px; pointer-events: none; }
43	        .group-band .group-label { position: absolute; top: -8px; left: 8px; font-size: 10px; background: #16213e; color: #888; padding: 0 6px; letter-spacing: 0.5px; text-transform: uppercase; }
44	
45	        /* Pin row — horizontal strip above the dashboard showing agents the
46	           user has explicitly pinned. Pinned agents are excluded from the
47	           heat-sized treemap so their visible size stays stable. */
48	        .pin-row { display: none; gap: 6px; padding: 6px 8px 0; overflow-x: auto; flex-shrink: 0; }
49	        .pin-row.visible { display: flex; }
50	        .pin-cell { flex: 0 0 auto; width: 180px; height: 82px; border: 1px solid #0f3460; border-radius: 6px; background: #16213e; padding: 6px 8px; display: flex; flex-direction: column; gap: 3px; cursor: pointer; position: relative; }
51	        .pin-cell:hover { border-color: #4ecca3; }
52	        .pin-cell .pin-head { display: flex; align-items: center; gap: 4px; font-size: 11px; min-width: 0; }
53	        .pin-cell .pin-name { font-weight: 600; color: #c9d1d9; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; flex: 1; }
54	        .pin-cell .pin-state { font-size: 10px; padding: 1px 5px; }
55	        .pin-cell .pin-body { display: flex; align-items: center; gap: 4px; min-width: 0; }
56	        .pin-cell .sparkline { flex-shrink: 0; width: 44px; height: 14px; }
57	        .pin-cell .sparkline path { fill: none; stroke: #4ecca3; stroke-width: 1.5; }
58	        .pin-cell .pin-lastline { flex: 1; min-width: 0; font-family: monospace; font-size: 9px; color: #6b7280; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
59	        .pin-cell .pin-unpin { position: absolute; top: 2px; right: 4px; font-size: 14px; color: #6b7280; cursor: pointer; line-height: 1; padding: 0 2px; background: transparent; border: none; }
60	        .pin-cell .pin-unpin:hover { color: #e94560; }
61	        .pin-cell .pin-icon { color: #fbbf24; flex-shrink: 0; font-size: 10px; }
62	
63	        /* Tile action buttons injected into agent-header + compact-head. */
64	        .tile-actions { display: flex; gap: 4px; flex-shrink: 0; }
65	        .tile-actions button { background: transparent; border: 1px solid #0f3460; color: #888; font-size: 11px; padding: 2px 6px; border-radius: 3px; cursor: pointer; }
66	        .tile-actions button:hover { background: #0f3460; color: #c9d1d9; }
67	        .tile-actions .btn-pin.pinned { color: #fbbf24; border-color: #fbbf24; }
68	
69	        /* Treemap mode: dashboard becomes an absolutely-positioned canvas.
70	           Tiles get their inset from computeLayout(). Smooth transitions
71	           keep the layout from feeling jittery at the 1.5s refresh cadence. */
72	        .dashboard.treemap-mode { display: block; position: relative; overflow: hidden; padding: 4px; gap: 0; }
73	        /* No transitions on position/size — instant snaps read as less
74	           "zoomy" than animated changes when the treemap recomputes. */
75	        .dashboard.treemap-mode .agent-panel,
76	        .dashboard.treemap-mode .agent-compact {
77	            position: absolute;
78	            min-height: 0;
79	        }
80	        .dashboard.treemap-mode .agent-panel.focus { outline: 2px solid #e94560; outline-offset: -2px; }
81	
82	        /* Selected window (click on a header) — accent outline so the
83	           user can see which window will receive bare-key commands in
84	           step 5. Distinct from the step-3 .focus outline which was
85	           auto-picked; this one is explicitly click-driven. */
86	        .dashboard.treemap-mode .agent-panel.selected { outline: 2px solid #4ecca3; outline-offset: -2px; }
87	
88	        /* Per-window chrome icon buttons (header right side). */
89	        .agent-header .tile-actions .btn-icon {
90	            background: transparent; border: 1px solid transparent;
91	            color: #888; font-size: 12px; padding: 1px 5px; line-height: 1;
92	            border-radius: 3px; cursor: pointer; min-width: 22px; text-align: center;
93	        }
94	        .agent-header .tile-actions .btn-icon:hover { background: #0f3460; color: #c9d1d9; border-color: #0f3460; }
95	        .agent-header .tile-actions .btn-pin.pinned { color: #fbbf24; border-color: #fbbf24; }
96	        .agent-header .tile-actions .btn-delete:hover { color: #fca5a5; border-color: #7f1d1d; background: #7f1d1d; }
97	
98	        /* Bottom dock — strip of minimized windows at the bottom of
99	           the dashboard area, always visible when any window is
100	           minimized. */

100	           minimized. */
101	        .window-dock { display: none; gap: 6px; padding: 6px 8px; border-top: 1px solid #0f3460; background: #16213e; overflow-x: auto; flex-shrink: 0; }
102	        .window-dock.visible { display: flex; }
103	        .dock-cell { flex: 0 0 auto; width: 180px; height: 48px; border: 1px solid #0f3460; border-radius: 4px; background: #0d1117; padding: 4px 8px; display: flex; flex-direction: column; gap: 2px; cursor: pointer; position: relative; overflow: hidden; }
104	        .dock-cell:hover { border-color: #4ecca3; }
105	        .dock-cell .dock-head { display: flex; align-items: center; gap: 4px; font-size: 11px; min-width: 0; }
106	        .dock-cell .dock-name { font-weight: 600; color: #c9d1d9; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; flex: 1; }
107	        .dock-cell .dock-role { font-size: 9px; color: #888; text-transform: uppercase; flex-shrink: 0; }
108	        .dock-cell .dock-state { font-size: 9px; padding: 1px 4px; }
109	        .dock-cell .dock-last { font-family: monospace; font-size: 9px; color: #6b7280; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
110	
111	        .agent-panel { display: flex; flex-direction: column; border: 1px solid #0f3460; border-radius: 6px; background: #16213e; min-height: 300px; overflow: auto; }
112	        .agent-header { padding: 8px 12px; display: flex; align-items: center; gap: 8px; border-bottom: 1px solid #0f3460; flex-shrink: 0; }
113	        .agent-header .agent-name { font-size: 14px; font-weight: 600; color: #c9d1d9; }
114	        .agent-header .agent-role { font-size: 11px; color: #888; text-transform: uppercase; letter-spacing: 0.5px; }
115	        .agent-header .spacer { flex: 1; }
116	
117	        .state-badge { font-size: 11px; padding: 2px 8px; border-radius: 10px; font-weight: 500; white-space: nowrap; }
118	        .state-starting    { background: #1f2937; color: #9ca3af; }
119	        .state-running     { background: #064e3b; color: #34d399; }
120	        .state-idle        { background: #1e3a5f; color: #60a5fa; }
121	        .state-awaiting_human_input { background: #78350f; color: #fbbf24; }
122	        .state-busy        { background: #4c1d95; color: #a78bfa; }
123	        .state-blocked     { background: #7f1d1d; color: #fca5a5; }
124	        .state-completed_task { background: #064e3b; color: #6ee7b7; }
125	        .state-error       { background: #7f1d1d; color: #f87171; }
126	        .state-disconnected { background: #1f2937; color: #6b7280; }
127	
128	        .agent-terminal { flex: 1; min-height: 0; background: #0d1117; cursor: text; overflow: hidden; position: relative; }
129	        .agent-terminal:focus-within { outline: 1px solid #e94560; outline-offset: -1px; }
130	        /* Visual scaler around xterm. xterm always renders at native rows*cols
131	           (no fit-addon after spawn); this wrapper applies a discrete
132	           scale so tile size changes are pure DOM work and the PTY never
133	           sees layout churn. */
134	        .term-scale { position: absolute; top: 0; left: 0; transform-origin: top left; transform: scale(var(--term-k, 1)); }
135	        .agent-controls { display: flex; gap: 6px; padding: 6px 8px; align-items: center; border-top: 1px solid #0f3460; flex-shrink: 0; }
136	        .agent-controls input { flex: 1; padding: 6px 10px; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-family: monospace; font-size: 13px; outline: none; }
137	        .agent-controls input:focus { border-color: #e94560; }
138	        .agent-controls button { padding: 6px 12px; border: none; border-radius: 4px; cursor: pointer; font-size: 12px; font-weight: 500; }
139	        .btn-send { background: #4ecca3; color: #1a1a2e; }
140	        .btn-send:hover { background: #3db892; }
141	        .btn-ctrl-c { background: #e94560; color: #fff; font-size: 11px; padding: 6px 8px; }
142	        .btn-ctrl-c:hover { background: #d63851; }
143	
144	        .conn-dot { width: 8px; height: 8px; border-radius: 50%; display: inline-block; }
145	        .conn-dot.connected { background: #4ecca3; }
146	        .conn-dot.disconnected { background: #e94560; }
147	
148	        /* Compact tile — replaces an xterm panel when allotted space is
149	           too small for xterm to be readable. No xterm DOM inside; cheap
150	           to render many of these at once. */
151	        .agent-compact { display: flex; flex-direction: column; border: 1px solid #0f3460; border-radius: 6px; background: #16213e; overflow: hidden; cursor: pointer; min-height: 54px; padding: 6px 8px; gap: 4px; }
152	        .agent-compact:hover { border-color: #4ecca3; }
153	        .agent-compact .compact-head { display: flex; align-items: center; gap: 6px; font-size: 12px; min-width: 0; }
154	        .agent-compact .compact-name { font-weight: 600; color: #c9d1d9; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
155	        .agent-compact .compact-role { font-size: 10px; color: #888; text-transform: uppercase; letter-spacing: 0.4px; flex-shrink: 0; }
156	        .agent-compact .compact-spacer { flex: 1; }
157	        .agent-compact .state-badge { font-size: 10px; padding: 1px 6px; }
158	        .agent-compact .compact-body { display: flex; align-items: center; gap: 6px; min-width: 0; }
159	        .agent-compact .sparkline { flex-shrink: 0; width: 60px; height: 18px; }
160	        .agent-compact .sparkline path { fill: none; stroke: #4ecca3; stroke-width: 1.5; }
161	        .agent-compact .last-line { flex: 1; min-width: 0; font-family: monospace; font-size: 10px; color: #6b7280; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
162	        .agent-compact .focus-hint { font-size: 9px; color: #4ecca3; flex-shrink: 0; opacity: 0; transition: opacity 0.15s; }
163	        .agent-compact:hover .focus-hint { opacity: 1; }
164	
165	        /* View tabs */
166	        .view-tabs { display: flex; gap: 4px; margin-left: auto; }
167	        .view-tab { padding: 4px 12px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #888; cursor: pointer; font-size: 12px; }
168	        .view-tab.active { background: #0f3460; color: #e0e0e0; }
169	        .view-tab:hover { color: #e0e0e0; }
170	
171	        /* Wiki browser */
172	        .wiki-container { flex: 1; display: flex; min-height: 0; overflow: hidden; }
173	        .wiki-sidebar { width: 220px; border-right: 1px solid #0f3460; overflow-y: auto; padding: 8px 0; flex-shrink: 0; }
174	        .wiki-sidebar h3 { font-size: 12px; color: #888; padding: 4px 12px; text-transform: uppercase; letter-spacing: 0.5px; }
175	        .wiki-page-item { padding: 6px 12px; cursor: pointer; font-size: 13px; color: #c9d1d9; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
176	        .wiki-page-item:hover { background: #1e3a5f; }
177	        .wiki-page-item.active { background: #0f3460; color: #e94560; }
178	        .wiki-main { flex: 1; display: flex; flex-direction: column; min-width: 0; overflow: hidden; }
179	        .wiki-toolbar { padding: 8px 12px; border-bottom: 1px solid #0f3460; display: flex; align-items: center; gap: 8px; flex-shrink: 0; }
180	        .wiki-toolbar .page-title { font-size: 14px; font-weight: 600; color: #c9d1d9; flex: 1; }
181	        .wiki-toolbar button { padding: 4px 10px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #c9d1d9; cursor: pointer; font-size: 12px; }
182	        .wiki-toolbar button:hover { background: #0f3460; }
183	        .wiki-toolbar button.btn-save { background: #4ecca3; color: #1a1a2e; border-color: #4ecca3; }
184	        .wiki-toolbar button.btn-save:hover { background: #3db892; }
185	        .wiki-content { flex: 1; overflow-y: auto; padding: 16px 20px; }
186	        .wiki-content h1, .wiki-content h2, .wiki-content h3 { color: #c9d1d9; margin: 16px 0 8px; }
187	        .wiki-content h1 { font-size: 22px; border-bottom: 1px solid #0f3460; padding-bottom: 6px; }
188	        .wiki-content h2 { font-size: 18px; }
189	        .wiki-content p { margin: 8px 0; line-height: 1.6; }
190	        .wiki-content ul, .wiki-content ol { margin: 8px 0; padding-left: 24px; }
191	        .wiki-content a.wiki-link { color: #4ecca3; text-decoration: none; cursor: pointer; }
192	        .wiki-content a.wiki-link:hover { text-decoration: underline; }
193	        .wiki-edit-area { flex: 1; display: flex; flex-direction: column; padding: 8px; min-height: 0; }
194	        .wiki-edit-area textarea { flex: 1; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-family: 'JetBrains Mono', monospace; font-size: 13px; padding: 12px; resize: none; outline: none; }
195	        .wiki-edit-area textarea:focus { border-color: #e94560; }
196	        .wiki-conflict { background: #7f1d1d; border: 1px solid #f87171; border-radius: 4px; padding: 10px 14px; margin: 8px; color: #fca5a5; font-size: 13px; }
197	        .wiki-new-page { display: flex; gap: 6px; padding: 8px 12px; border-top: 1px solid #0f3460; }
198	        .wiki-new-page input { flex: 1; padding: 4px 8px; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-size: 12px; outline: none; }
199	        .wiki-new-page button { padding: 4px 10px; background: #4ecca3; color: #1a1a2e; border: none; border-radius: 4px; cursor: pointer; font-size: 12px; }
200	
201	        /* Events log */
202	        .events-container { flex: 1; display: flex; flex-direction: column; min-height: 0; overflow: hidden; padding: 8px; }
203	        .events-toolbar { display: flex; align-items: center; gap: 8px; padding: 8px; flex-shrink: 0; }
204	        .events-toolbar h2 { font-size: 16px; color: #c9d1d9; flex: 1; }
205	        .events-toolbar button { padding: 4px 10px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #c9d1d9; cursor: pointer; font-size: 12px; }
206	        .events-toolbar button:hover { background: #0f3460; }
207	        .events-columns { flex: 1; display: grid; grid-template-columns: 1fr 1fr; gap: 8px; min-height: 0; overflow: hidden; }
208	        .events-column { display: flex; flex-direction: column; min-height: 0; overflow: hidden; }
209	        .events-column-header { font-size: 13px; font-weight: 600; color: #c9d1d9; padding: 6px 10px; background: #16213e; border: 1px solid #0f3460; border-radius: 6px 6px 0 0; flex-shrink: 0; }
210	        .events-column-header .col-arrow { margin: 0 4px; color: #e94560; }
211	        .events-list { flex: 1; overflow-y: auto; }
212	        .event-card { border: 1px solid #0f3460; border-radius: 6px; background: #16213e; padding: 10px 14px; margin-bottom: 6px; }
213	        .event-card .event-header { display: flex; align-items: center; gap: 8px; margin-bottom: 4px; }
214	        .event-card .event-kind { font-size: 11px; padding: 2px 8px; border-radius: 10px; font-weight: 500; }
215	        .kind-feature_request { background: #1e3a5f; color: #60a5fa; }
216	        .kind-bug_fix_request { background: #7f1d1d; color: #fca5a5; }
217	        .kind-completion_notice { background: #064e3b; color: #6ee7b7; }
218	        .kind-blocked_notice { background: #78350f; color: #fbbf24; }
219	        .kind-needs_info { background: #4c1d95; color: #a78bfa; }
220	        .kind-verification_request { background: #064e3b; color: #34d399; }
221	        .event-card .event-summary { font-size: 13px; color: #e0e0e0; }
222	        .event-card .event-meta { font-size: 11px; color: #888; margin-top: 4px; display: flex; gap: 12px; }
223	        .event-card .event-decision { font-size: 11px; padding: 2px 6px; border-radius: 4px; }
224	        .decision-deliver { background: #064e3b; color: #34d399; }
225	        .decision-escalate { background: #7f1d1d; color: #fca5a5; }
226	        .decision-broadcast { background: #1e3a5f; color: #60a5fa; }
227	        .escalation-banner { background: #7f1d1d; border: 1px solid #f87171; border-radius: 6px; padding: 10px 14px; margin-bottom: 8px; color: #fca5a5; font-size: 13px; display: flex; align-items: center; gap: 8px; }
228	        .escalation-banner .esc-icon { font-size: 18px; }
229	
230	        /* Saga view */
231	        .saga-container { flex: 1; display: flex; flex-direction: column; min-height: 0; overflow: hidden; padding: 8px; }
232	        .saga-toolbar { display: flex; align-items: center; gap: 8px; padding: 8px; flex-shrink: 0; }
233	        .saga-toolbar h2 { font-size: 16px; color: #c9d1d9; flex: 1; }
234	        .saga-toolbar button { padding: 4px 10px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #c9d1d9; cursor: pointer; font-size: 12px; }
235	        .saga-toolbar button:hover { background: #0f3460; }
236	        .saga-toolbar .btn-distill { background: #4c1d95; color: #a78bfa; border-color: #4c1d95; }
237	        .saga-toolbar .btn-distill:hover { background: #5b21b6; }
238	        .saga-grid { flex: 1; display: grid; gap: 8px; min-height: 0; overflow: auto; }
239	        .saga-grid.saga-cols-1 { grid-template-columns: 1fr; }
240	        .saga-grid.saga-cols-2 { grid-template-columns: 1fr 1fr; }
241	        .saga-grid.saga-cols-3 { grid-template-columns: 1fr 1fr 1fr; }
242	        .saga-grid.saga-cols-4 { grid-template-columns: 1fr 1fr 1fr 1fr; }
243	        .saga-panel { display: flex; flex-direction: column; border: 1px solid #0f3460; border-radius: 6px; background: #16213e; min-height: 0; overflow: hidden; }
244	        .saga-panel-header { padding: 8px 12px; display: flex; align-items: center; gap: 8px; border-bottom: 1px solid #0f3460; flex-shrink: 0; }
245	        .saga-panel-header .saga-agent-name { font-size: 14px; font-weight: 600; color: #c9d1d9; }
246	        .saga-panel-header .saga-agent-role { font-size: 11px; color: #888; text-transform: uppercase; letter-spacing: 0.5px; }
247	        .saga-panel-header .spacer { flex: 1; }
248	        .saga-panel-header .saga-status-badge { font-size: 11px; padding: 2px 8px; border-radius: 10px; font-weight: 500; }
249	        .saga-panel-header .saga-active { background: #064e3b; color: #34d399; }

