.window-dock { display: none; gap: 6px; padding: 6px 8px; border-top: 1px solid #0f3460; background: #16213e; overflow-x: auto; flex-shrink: 0; }
.window-dock.visible { display: flex; }
.dock-cell { flex: 0 0 auto; width: 180px; height: 48px; border: 1px solid #0f3460; border-radius: 4px; background: #0d1117; padding: 4px 8px; display: flex; flex-direction: column; gap: 2px; cursor: pointer; position: relative; overflow: hidden; }
.dock-cell:hover { border-color: #4ecca3; }
.dock-cell .dock-head { display: flex; align-items: center; gap: 4px; font-size: 11px; min-width: 0; }
.dock-cell .dock-name { font-weight: 600; color: #c9d1d9; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; flex: 1; }
.dock-cell .dock-role { font-size: 9px; color: #888; text-transform: uppercase; flex-shrink: 0; }
.dock-cell .dock-state { font-size: 9px; padding: 1px 4px; }
.dock-cell .dock-last { font-family: monospace; font-size: 9px; color: #6b7280; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

.agent-panel { display: flex; flex-direction: column; border: 1px solid #0f3460; border-radius: 6px; background: #16213e; min-height: 300px; overflow: auto; }
.agent-header { padding: 8px 12px; display: flex; align-items: center; gap: 8px; border-bottom: 1px solid #0f3460; flex-shrink: 0; }
.agent-header .agent-name { font-size: 14px; font-weight: 600; color: #c9d1d9; }
.agent-header .agent-role { font-size: 11px; color: #888; text-transform: uppercase; letter-spacing: 0.5px; }
.agent-header .spacer { flex: 1; }

.state-badge { font-size: 11px; padding: 2px 8px; border-radius: 10px; font-weight: 500; white-space: nowrap; }
.state-starting    { background: #1f2937; color: #9ca3af; }
.state-running     { background: #064e3b; color: #34d399; }
.state-idle        { background: #1e3a5f; color: #60a5fa; }
.state-awaiting_human_input { background: #78350f; color: #fbbf24; }
.state-busy        { background: #4c1d95; color: #a78bfa; }
.state-blocked     { background: #7f1d1d; color: #fca5a5; }
.state-completed_task { background: #064e3b; color: #6ee7b7; }
.state-error       { background: #7f1d1d; color: #f87171; }
.state-disconnected { background: #1f2937; color: #6b7280; }

.agent-terminal { flex: 1; min-height: 0; background: #0d1117; cursor: text; overflow: hidden; position: relative; }
.agent-terminal:focus-within { outline: 1px solid #e94560; outline-offset: -1px; }
/* Visual scaler around xterm. xterm always renders at native rows*cols
   (no fit-addon after spawn); this wrapper applies a discrete
   scale so tile size changes are pure DOM work and the PTY never
   sees layout churn. */
.term-scale { position: absolute; top: 0; left: 0; transform-origin: top left; transform: scale(var(--term-k, 1)); }
.agent-controls { display: flex; gap: 6px; padding: 6px 8px; align-items: center; border-top: 1px solid #0f3460; flex-shrink: 0; }
.agent-controls input { flex: 1; padding: 6px 10px; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-family: monospace; font-size: 13px; outline: none; }
.agent-controls input:focus { border-color: #e94560; }
.agent-controls button { padding: 6px 12px; border: none; border-radius: 4px; cursor: pointer; font-size: 12px; font-weight: 500; }
.btn-send { background: #4ecca3; color: #1a1a2e; }
.btn-send:hover { background: #3db892; }
.btn-ctrl-c { background: #e94560; color: #fff; font-size: 11px; padding: 6px 8px; }
.btn-ctrl-c:hover { background: #d63851; }

.conn-dot { width: 8px; height: 8px; border-radius: 50%; display: inline-block; }
.conn-dot.connected { background: #4ecca3; }
.conn-dot.disconnected { background: #e94560; }

/* Compact tile — replaces an xterm panel when allotted space is
   too small for xterm to be readable. No xterm DOM inside; cheap
   to render many of these at once. */
.agent-compact { display: flex; flex-direction: column; border: 1px solid #0f3460; border-radius: 6px; background: #16213e; overflow: hidden; cursor: pointer; min-height: 54px; padding: 6px 8px; gap: 4px; }
.agent-compact:hover { border-color: #4ecca3; }
.agent-compact .compact-head { display: flex; align-items: center; gap: 6px; font-size: 12px; min-width: 0; }
.agent-compact .compact-name { font-weight: 600; color: #c9d1d9; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.agent-compact .compact-role { font-size: 10px; color: #888; text-transform: uppercase; letter-spacing: 0.4px; flex-shrink: 0; }
.agent-compact .compact-spacer { flex: 1; }
.agent-compact .state-badge { font-size: 10px; padding: 1px 6px; }
.agent-compact .compact-body { display: flex; align-items: center; gap: 6px; min-width: 0; }
.agent-compact .sparkline { flex-shrink: 0; width: 60px; height: 18px; }
.agent-compact .sparkline path { fill: none; stroke: #4ecca3; stroke-width: 1.5; }
.agent-compact .last-line { flex: 1; min-width: 0; font-family: monospace; font-size: 10px; color: #6b7280; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.agent-compact .focus-hint { font-size: 9px; color: #4ecca3; flex-shrink: 0; opacity: 0; transition: opacity 0.15s; }
.agent-compact:hover .focus-hint { opacity: 1; }

/* View tabs */
.view-tabs { display: flex; gap: 4px; margin-left: auto; }
.view-tab { padding: 4px 12px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #888; cursor: pointer; font-size: 12px; }
.view-tab.active { background: #0f3460; color: #e0e0e0; }
.view-tab:hover { color: #e0e0e0; }

/* Wiki browser */
.wiki-container { flex: 1; display: flex; min-height: 0; overflow: hidden; }
.wiki-sidebar { width: 220px; border-right: 1px solid #0f3460; overflow-y: auto; padding: 8px 0; flex-shrink: 0; }
.wiki-sidebar h3 { font-size: 12px; color: #888; padding: 4px 12px; text-transform: uppercase; letter-spacing: 0.5px; }
.wiki-page-item { padding: 6px 12px; cursor: pointer; font-size: 13px; color: #c9d1d9; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.wiki-page-item:hover { background: #1e3a5f; }
.wiki-page-item.active { background: #0f3460; color: #e94560; }
.wiki-main { flex: 1; display: flex; flex-direction: column; min-width: 0; overflow: hidden; }
.wiki-toolbar { padding: 8px 12px; border-bottom: 1px solid #0f3460; display: flex; align-items: center; gap: 8px; flex-shrink: 0; }
.wiki-toolbar .page-title { font-size: 14px; font-weight: 600; color: #c9d1d9; flex: 1; }
.wiki-toolbar button { padding: 4px 10px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #c9d1d9; cursor: pointer; font-size: 12px; }
.wiki-toolbar button:hover { background: #0f3460; }
.wiki-toolbar button.btn-save { background: #4ecca3; color: #1a1a2e; border-color: #4ecca3; }
.wiki-toolbar button.btn-save:hover { background: #3db892; }
.wiki-content { flex: 1; overflow-y: auto; padding: 16px 20px; }
.wiki-content h1, .wiki-content h2, .wiki-content h3 { color: #c9d1d9; margin: 16px 0 8px; }
.wiki-content h1 { font-size: 22px; border-bottom: 1px solid #0f3460; padding-bottom: 6px; }
.wiki-content h2 { font-size: 18px; }
.wiki-content p { margin: 8px 0; line-height: 1.6; }
.wiki-content ul, .wiki-content ol { margin: 8px 0; padding-left: 24px; }
.wiki-content a.wiki-link { color: #4ecca3; text-decoration: none; cursor: pointer; }
.wiki-content a.wiki-link:hover { text-decoration: underline; }
.wiki-edit-area { flex: 1; display: flex; flex-direction: column; padding: 8px; min-height: 0; }
.wiki-edit-area textarea { flex: 1; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-family: 'JetBrains Mono', monospace; font-size: 13px; padding: 12px; resize: none; outline: none; }
.wiki-edit-area textarea:focus { border-color: #e94560; }
.wiki-conflict { background: #7f1d1d; border: 1px solid #f87171; border-radius: 4px; padding: 10px 14px; margin: 8px; color: #fca5a5; font-size: 13px; }
.wiki-new-page { display: flex; gap: 6px; padding: 8px 12px; border-top: 1px solid #0f3460; }
.wiki-new-page input { flex: 1; padding: 4px 8px; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-size: 12px; outline: none; }
.wiki-new-page button { padding: 4px 10px; background: #4ecca3; color: #1a1a2e; border: none; border-radius: 4px; cursor: pointer; font-size: 12px; }

/* Events log */
.events-container { flex: 1; display: flex; flex-direction: column; min-height: 0; overflow: hidden; padding: 8px; }
.events-toolbar { display: flex; align-items: center; gap: 8px; padding: 8px; flex-shrink: 0; }
.events-toolbar h2 { font-size: 16px; color: #c9d1d9; flex: 1; }
.events-toolbar button { padding: 4px 10px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #c9d1d9; cursor: pointer; font-size: 12px; }
.events-toolbar button:hover { background: #0f3460; }
.events-columns { flex: 1; display: grid; grid-template-columns: 1fr 1fr; gap: 8px; min-height: 0; overflow: hidden; }
.events-column { display: flex; flex-direction: column; min-height: 0; overflow: hidden; }
.events-column-header { font-size: 13px; font-weight: 600; color: #c9d1d9; padding: 6px 10px; background: #16213e; border: 1px solid #0f3460; border-radius: 6px 6px 0 0; flex-shrink: 0; }
.events-column-header .col-arrow { margin: 0 4px; color: #e94560; }
.events-list { flex: 1; overflow-y: auto; }
.event-card { border: 1px solid #0f3460; border-radius: 6px; background: #16213e; padding: 10px 14px; margin-bottom: 6px; }
.event-card .event-header { display: flex; align-items: center; gap: 8px; margin-bottom: 4px; }
.event-card .event-kind { font-size: 11px; padding: 2px 8px; border-radius: 10px; font-weight: 500; }
.kind-feature_request { background: #1e3a5f; color: #60a5fa; }
.kind-bug_fix_request { background: #7f1d1d; color: #fca5a5; }
.kind-completion_notice { background: #064e3b; color: #6ee7b7; }
.kind-blocked_notice { background: #78350f; color: #fbbf24; }
.kind-needs_info { background: #4c1d95; color: #a78bfa; }
.kind-verification_request { background: #064e3b; color: #34d399; }
.event-card .event-summary { font-size: 13px; color: #e0e0e0; }
.event-card .event-meta { font-size: 11px; color: #888; margin-top: 4px; display: flex; gap: 12px; }
.event-card .event-decision { font-size: 11px; padding: 2px 6px; border-radius: 4px; }
.decision-deliver { background: #064e3b; color: #34d399; }
.decision-escalate { background: #7f1d1d; color: #fca5a5; }
.decision-broadcast { background: #1e3a5f; color: #60a5fa; }
.escalation-banner { background: #7f1d1d; border: 1px solid #f87171; border-radius: 6px; padding: 10px 14px; margin-bottom: 8px; color: #fca5a5; font-size: 13px; display: flex; align-items: center; gap: 8px; }
.escalation-banner .esc-icon { font-size: 18px; }

/* Saga view */
.saga-container { flex: 1; display: flex; flex-direction: column; min-height: 0; overflow: hidden; padding: 8px; }
.saga-toolbar { display: flex; align-items: center; gap: 8px; padding: 8px; flex-shrink: 0; }
.saga-toolbar h2 { font-size: 16px; color: #c9d1d9; flex: 1; }
.saga-toolbar button { padding: 4px 10px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #c9d1d9; cursor: pointer; font-size: 12px; }
.saga-toolbar button:hover { background: #0f3460; }
.saga-toolbar .btn-distill { background: #4c1d95; color: #a78bfa; border-color: #4c1d95; }
.saga-toolbar .btn-distill:hover { background: #5b21b6; }
.saga-grid { flex: 1; display: grid; gap: 8px; min-height: 0; overflow: auto; }
.saga-grid.saga-cols-1 { grid-template-columns: 1fr; }
.saga-grid.saga-cols-2 { grid-template-columns: 1fr 1fr; }
.saga-grid.saga-cols-3 { grid-template-columns: 1fr 1fr 1fr; }
.saga-grid.saga-cols-4 { grid-template-columns: 1fr 1fr 1fr 1fr; }
.saga-panel { display: flex; flex-direction: column; border: 1px solid #0f3460; border-radius: 6px; background: #16213e; min-height: 0; overflow: hidden; }
.saga-panel-header { padding: 8px 12px; display: flex; align-items: center; gap: 8px; border-bottom: 1px solid #0f3460; flex-shrink: 0; }
.saga-panel-header .saga-agent-name { font-size: 14px; font-weight: 600; color: #c9d1d9; }
.saga-panel-header .saga-agent-role { font-size: 11px; color: #888; text-transform: uppercase; letter-spacing: 0.5px; }
.saga-panel-header .spacer { flex: 1; }
.saga-panel-header .saga-status-badge { font-size: 11px; padding: 2px 8px; border-radius: 10px; font-weight: 500; }
.saga-panel-header .saga-active { background: #064e3b; color: #34d399; }

