//
// Layout is mode-driven: the step-1 foundation supports `tiled`
// only. Later saga steps add stack + carousel. Coord is always
// placed prominently (left slice) regardless of sort order so the
// demo has a clear "primary window".

const COORD_FRAC = 0.55; // coord takes 55% of dashboard width
const TILE_GAP = 4;

function gridRects(rect, items) {
    // Simple grid of equal cells. Picks cols×rows roughly matching
    // the rect's aspect ratio. Small-N uses a single column so a
    // vertically-tall sidebar doesn't produce micro-thin tiles.
    if (items.length === 0) return [];
    const aspect = rect.w / rect.h;
    let cols = Math.max(1, Math.round(Math.sqrt(items.length * aspect)));
    if (items.length <= 3 && aspect < 1.2) cols = 1;
    const rows = Math.ceil(items.length / cols);
    const cellW = Math.floor(rect.w / cols);
    const cellH = Math.floor(rect.h / rows);
    const out = [];
    for (let i = 0; i < items.length; i++) {
        const r = Math.floor(i / cols);
        const c = i % cols;
        out.push({
            id: items[i].id,
            x: rect.x + c * cellW,
            y: rect.y + r * cellH,
            w: Math.max(80, cellW - TILE_GAP),
            h: Math.max(80, cellH - TILE_GAP),
        });
    }
    return out;
}

function computeLayout(container) {
    const all = buildLayoutItems();
    if (all.length === 0) return { windows: [], minimized: [] };

    const rect = {
        x: 4,
        y: 4,
        w: Math.max(240, container.clientWidth - 8),
        h: Math.max(200, container.clientHeight - 8),
    };

    // Separate minimized and maximized from normal-state agents.
    const minimized = all.filter((it) => windowState(it.id) === 'minimized');
    const maxed = all.find((it) => windowState(it.id) === 'maximized');

    // Maximized short-circuits everything: one window fills ~80%
    // centered, every other window is implicitly dock-minimized
    // for the duration (without mutating their stored state).
    if (maxed) {
        const maxW = Math.floor(rect.w * 0.8);
        const maxH = Math.floor(rect.h * 0.9);
        const maxRect = {
            id: maxed.id,
            x: rect.x + Math.floor((rect.w - maxW) / 2),
            y: rect.y + Math.floor((rect.h - maxH) / 2),
            w: maxW, h: maxH,
        };
        const implicitDock = all.filter((it) => it.id !== maxed.id);
        return { windows: [maxRect], minimized: implicitDock };
    }

    // Otherwise lay out normal-state agents (dock minimized separately).
    const normal = all.filter((it) => windowState(it.id) === 'normal');
    if (normal.length === 0) return { windows: [], minimized };

    const coordIdx = normal.findIndex((it) => roleOf(it.id) === 'coordinator');
    const coord = coordIdx >= 0 ? normal[coordIdx] : null;
    const workers = coord
        ? normal.filter((_, i) => i !== coordIdx)
        : normal.slice();

    if (!coord) return { windows: gridRects(rect, workers), minimized };
    if (workers.length === 0) {
        return { windows: [{ id: coord.id, ...rect }], minimized };
    }
    const coordW = Math.floor(rect.w * COORD_FRAC) - TILE_GAP / 2;
    const coordRect = { id: coord.id, x: rect.x, y: rect.y, w: coordW, h: rect.h };
    const workerArea = {
        x: rect.x + coordW + TILE_GAP,
        y: rect.y,
        w: rect.w - coordW - TILE_GAP,
        h: rect.h,
    };
    return {
        windows: [coordRect, ...gridRects(workerArea, workers)],
        minimized,
    };
}

/** Partition items by a group key drawn from agent meta. Returns an
 *  ordered Map so iteration order is stable (largest first). */
function groupItems(items, key) {
    const groups = new Map();
    for (const it of items) {
        const entry = agents.get(it.id);
        const info = entry?.info || {};
        const spec = info.spec || {};
        let g;
        if (key === 'role') g = (info.role || 'other').toLowerCase();
        else if (key === 'project') g = spec.project || info.name || 'other';
        else g = 'other';
        if (!groups.has(g)) groups.set(g, []);
        groups.get(g).push(it);
    }
    // Sort by total value desc so the biggest group gets the
    // largest rect.
    const sorted = Array.from(groups.entries())
        .map(([k, arr]) => ({
            key: k,
            items: arr,
            total: arr.reduce((s, i) => s + i.value, 0),
        }))
        .sort((a, b) => b.total - a.total);
    return sorted;
}

/** Lay out grouped items: split `rect` horizontally (or vertically if
 *  the rect is taller than wide) by group weights, then squarify
 *  inside each sub-rect. Returns {tiles, bands} where bands are
 *  overlay rects (for group outlines). */
function groupedSquarify(rect, groups) {
    if (groups.length === 0) return { tiles: [], bands: [] };
    const total = groups.reduce((s, g) => s + g.total, 0);
    if (total <= 0) return { tiles: [], bands: [] };

    const horizontal = rect.w >= rect.h;
    const tiles = [];
    const bands = [];
    let cursor = horizontal ? rect.x : rect.y;
    const GAP = 4;
    for (let i = 0; i < groups.length; i++) {
        const g = groups[i];
        const frac = g.total / total;
        let sub;
        const thisGap = i === groups.length - 1 ? 0 : GAP;
        if (horizontal) {
            const w = Math.max(40, Math.floor(rect.w * frac) - thisGap);
            sub = { x: cursor, y: rect.y, w, h: rect.h };
            cursor += w + thisGap;
        } else {
            const h = Math.max(40, Math.floor(rect.h * frac) - thisGap);
            sub = { x: rect.x, y: cursor, w: rect.w, h };
            cursor += h + thisGap;
        }
        const placed = squarify({ x: sub.x + 2, y: sub.y + 12, w: sub.w - 4, h: sub.h - 14 }, g.items);
        for (const t of placed) tiles.push(t);
        bands.push({ key: g.key, ...sub });
    }
    return { tiles, bands };
}

function ensureModeFor(id, rect) {
    // Pick xterm vs compact based on the rect fit, using the step-3
    // scale picker. Switches the tile mode if needed.
    const a = agents.get(id);
    if (!a) return;
    const { w: natW, h: natH } = nativeTermSize(id);
    const k = pickTermScale(rect.w - 16, rect.h - 40, natW, natH);
    const wantCompact = k === null;
    if (wantCompact && a.mode !== 'compact') toggleCompactMode(id);
    if (!wantCompact && a.mode !== 'xterm') toggleCompactMode(id);
}

function applyLayout(layout) {
    const dashboard = document.getElementById('dashboard');
    if (!dashboard) return;
    const windows = layout.windows || [];
    const minimized = layout.minimized || [];
    atnDebug.log('apply', {
        count: windows.length,
        ids: windows.map(w => `${w.id}(${Math.round(w.w)}x${Math.round(w.h)})`),
        min: minimized.map(m => m.id),
    });
    const place = (id, rect) => {
        const el = document.getElementById(`panel-${id}`)
            || document.getElementById(`compact-${id}`);
        if (!el) return;
        el.style.left = `${rect.x}px`;
        el.style.top = `${rect.y}px`;
        el.style.width = `${rect.w}px`;
        el.style.height = `${rect.h}px`;
        if (el.classList.contains('agent-panel')) {
            el.classList.remove('focus');
        }
    };
    // Move any not-in-layout panels off-screen (pinned agents,
    // filter misses, minimized agents — the dock shows those).
    const visibleIds = new Set(windows.map(w => w.id));
    for (const id of agents.keys()) {
        if (layoutState.pins.has(id)) continue;
        if (visibleIds.has(id)) continue;
        const el = document.getElementById(`panel-${id}`)
            || document.getElementById(`compact-${id}`);
        if (el) {
            el.style.left = '-9999px';
            el.style.top = '-9999px';
            el.style.width = '0';
            el.style.height = '0';
        }
    }
    for (const w of windows) {
        ensureModeFor(w.id, w);
        place(w.id, w);
    }
    // Selected outline follows state.
    document.querySelectorAll('.agent-panel.selected').forEach(el => el.classList.remove('selected'));
    if (layoutState.selectedId) {
        const sel = document.getElementById(`panel-${layoutState.selectedId}`);
        if (sel) {
            sel.classList.add('selected');
            // Selected non-minimized tile gets full xterm fit.
            fitSelectedTerm(layoutState.selectedId);
        }
    }
    // Step 1 has no group bands; clear any that may have been left
    // over from a stale layout.
    dashboard.querySelectorAll('.group-band').forEach((b) => b.remove());
    renderWindowDock(minimized);
    // Refresh the pin row so (filtered) labels update.
    syncPinFilteredLabels();
    // After positions change, update per-xterm scales.
    updateTileScales();
}

