//   - Clicking inside the xterm body puts focus there; all keys
//     route to the PTY as usual.
//   - Clicking an empty area of the dashboard or pressing Esc
//     (step 5) deselects and restores any maximized window.

function windowSelect(id) {
    layoutState.selectedId = id;
    document.querySelectorAll('.agent-panel.selected').forEach((el) => {
        el.classList.remove('selected');
    });
    if (id) {
        const el = document.getElementById(`panel-${id}`);
        if (el) el.classList.add('selected');
        // Selected tile gets a crisp xterm at its real size.
        fitSelectedTerm(id);
    }
}

function fitSelectedTerm(id) {
    const a = agents.get(id);
    if (!a || !a.fitAddon) return;
    try {
        a.fitAddon.fit();
        syncPtySize(id, a.term);
    } catch (_) { /* xterm not rendered yet */ }
}

function windowMinimize(id) {
    ensureWindow(id).state = 'minimized';
    if (layoutState.selectedId === id) layoutState.selectedId = null;
    saveLayoutPrefs();
    applyLayoutFresh();
}

function windowMaximizeToggle(id) {
    const w = ensureWindow(id);
    if (w.state === 'maximized') {
        w.state = 'normal';
    } else {
        // Only one maximized window at a time — restore any existing.
        for (const other of agents.keys()) {
            const ow = layoutState.windows[other];
            if (ow && ow.state === 'maximized') ow.state = 'normal';
        }
        w.state = 'maximized';
        layoutState.selectedId = id;
    }
    saveLayoutPrefs();
    applyLayoutFresh();
}

function windowRestore(id) {
    ensureWindow(id).state = 'normal';
    saveLayoutPrefs();
    applyLayoutFresh();
}

function applyLayoutFresh() {
    const dashboard = document.getElementById('dashboard');
    if (!dashboard) return;
    applyLayout(computeLayout(dashboard));
}

function confirmDelete(id) {
    if (!confirm(`Delete agent '${id}'? This cannot be undone.`)) return;
    fetch(`${API_BASE}/api/agents/${id}`, { method: 'DELETE' })
        .then(() => {
            const a = agents.get(id);
            if (a && a.evtSource) a.evtSource.close();
            if (a && a.panel) a.panel.remove();
            agents.delete(id);
            delete layoutState.windows[id];
            if (layoutState.selectedId === id) layoutState.selectedId = null;
            applyLayoutFresh();
            refreshDashboardLayout();
        });
}

function reconnectAgent(id) {
    fetch(`${API_BASE}/api/agents/${id}/reconnect`, { method: 'POST' })
        .then((res) => {
            if (!res.ok) return;
            const a = agents.get(id);
            if (a && a.evtSource) a.evtSource.close();
            setTimeout(() => connectSSE(id), 1000);
        });
}

