// exactly what's firing — useful when something looks jittery.
const atnDebug = {
    traceOn: false,
    trace(on = true) { this.traceOn = on; console.log(`atnDebug.trace: ${on}`); },
    log(event, data) {
        if (this.traceOn) console.debug(`[atn] ${event}`, data || '');
    },
};

// Focus-panel width fractions keyed by layoutState.focusSize:
// [minFrac, maxFrac] of the total viewport width.
const FOCUS_WIDTHS = { medium: [0.4, 0.5], large: [0.55, 0.7] };
const PINS_MAX = 6;
const LAYOUT_PREFS_KEY = 'atn-scale-ui-v1';

const layoutState = {
    focusId: null,
    freezeUntil: 0,
    // per-agent EWMA of raw heat from /api/agents/heat
    smoothed: new Map(),
    enabled: false,
    pins: new Set(),
    focusSize: 'medium', // 'medium' | 'large' (legacy — scale-UI)
    filterText: '',
    // Set of "transport:mosh", "role:worker", "state:error" etc.
    // Within a category chips OR; across categories they AND.
    filterChips: new Set(),
    groupBy: '', // '' | 'role' | 'project'
    // Windowed UI saga (step 1): layout + sort modes.
    layoutMode: 'tiled', // 'tiled' (step 1) | future 'stack' | 'carousel'
    sortMode: 'name',    // 'name' (step 1) | future 'recent'
    // Windowed UI saga (step 2): per-window state + click-selected.
    windows: {}, // { [id]: { state: 'normal'|'minimized'|'maximized', pinned: bool } }
    selectedId: null,
};

function ensureWindow(id) {
    if (!layoutState.windows[id]) {
        layoutState.windows[id] = {
            state: 'normal',
            pinned: layoutState.pins.has(id),
        };
    }
    return layoutState.windows[id];
}

function windowState(id) {
    return (layoutState.windows[id] && layoutState.windows[id].state) || 'normal';
}

function hasMaximized() {
    for (const id of agents.keys()) {
        if (windowState(id) === 'maximized') return id;
    }
    return null;
}

/** Returns true if agentId passes the current filter. Pinned agents
 *  are not auto-included here — callers decide whether to override
 *  (pin row shows pinned regardless; treemap does not). */
function matchesFilter(agentId) {
    const entry = agents.get(agentId);
    if (!entry) return false;
    const info = entry.info || {};
    const spec = info.spec || {};

    // Text match: fuzzy substring across name, project, role,
    // spec.host, spec.user. Case-insensitive.
    const q = (layoutState.filterText || '').trim().toLowerCase();
    if (q) {
        const hay = [
            info.name || agentId,
            spec.project || '',
            info.role || '',
            spec.host || '',
            spec.user || '',
            spec.agent || '',
        ].join(' ').toLowerCase();
        if (!hay.includes(q)) return false;
    }

    // Chips partitioned by category; within a category, any chip in
    // the set is a match (OR); across categories, all must match (AND).
    if (layoutState.filterChips.size > 0) {
        const byCat = new Map();
        for (const chip of layoutState.filterChips) {
            const [cat, val] = chip.split(':');
            if (!byCat.has(cat)) byCat.set(cat, new Set());
            byCat.get(cat).add(val);
        }
        const transport = (spec.transport || 'local').toLowerCase();
        const role = (info.role || '').toLowerCase();
        const stateKeyNow = stateKey(info.state || { state: 'idle' });
        for (const [cat, vals] of byCat) {
            let val;
            if (cat === 'transport') val = transport;
            else if (cat === 'role') val = role;
            else if (cat === 'state') val = stateKeyNow;
            else continue;
            if (!vals.has(val)) return false;
        }
    }
    return true;
}

function saveLayoutPrefs() {
    try {
        const data = JSON.stringify({
            pins: Array.from(layoutState.pins),
            focusId: layoutState.focusId,
            focusSize: layoutState.focusSize,
            filterText: layoutState.filterText,
            filterChips: Array.from(layoutState.filterChips),
            groupBy: layoutState.groupBy,
            layoutMode: layoutState.layoutMode,
            sortMode: layoutState.sortMode,
        });
        localStorage.setItem(LAYOUT_PREFS_KEY, data);
    } catch (_) { /* localStorage unavailable or full — ignore */ }
}

// --- Saved layouts ---
const SAVED_LAYOUTS_KEY = 'atn-scale-ui-saved-layouts-v1';

function listSavedLayouts() {
    try {
        return JSON.parse(localStorage.getItem(SAVED_LAYOUTS_KEY) || '{}') || {};
    } catch (_) {
        return {};
    }
}

function writeSavedLayouts(map) {
    try {
        localStorage.setItem(SAVED_LAYOUTS_KEY, JSON.stringify(map));
    } catch (_) {}
}

function saveNamedLayout(name) {
    if (!name) return;
    const map = listSavedLayouts();
    map[name] = {
        pins: Array.from(layoutState.pins),
        focusId: layoutState.focusId,
        focusSize: layoutState.focusSize,
        filterText: layoutState.filterText,
        filterChips: Array.from(layoutState.filterChips),
        groupBy: layoutState.groupBy,
    };
    writeSavedLayouts(map);
    refreshSavedLayoutsDropdown();
}

function applyNamedLayout(name) {
    const map = listSavedLayouts();
    const lyt = map[name];
    if (!lyt) return;
    layoutState.pins = new Set(lyt.pins || []);
    layoutState.focusId = lyt.focusId || null;
    layoutState.focusSize = lyt.focusSize === 'large' ? 'large' : 'medium';
    layoutState.filterText = lyt.filterText || '';
    layoutState.filterChips = new Set(lyt.filterChips || []);
    layoutState.groupBy = lyt.groupBy || '';
    saveLayoutPrefs();
    // Reflect state in the filter bar UI.
    const input = document.getElementById('filter-input');
    if (input) input.value = layoutState.filterText;
    document.querySelectorAll('.filter-bar .chip').forEach((c) => {
        c.classList.toggle('active', layoutState.filterChips.has(c.getAttribute('data-chip')));
    });
    const gSel = document.getElementById('group-by');
    if (gSel) gSel.value = layoutState.groupBy;
    renderPinRow();
    syncPinButtons();
    const dashboard = document.getElementById('dashboard');
    if (dashboard && layoutState.enabled) {
        applyLayout(computeLayout(dashboard));
    }
}

function deleteNamedLayout(name) {
    if (!name) return;
    const map = listSavedLayouts();
    delete map[name];
    writeSavedLayouts(map);
    refreshSavedLayoutsDropdown();
}

function refreshSavedLayoutsDropdown() {
    const sel = document.getElementById('saved-layouts');
    if (!sel) return;
    const map = listSavedLayouts();
    const names = Object.keys(map).sort();
    sel.innerHTML = '<option value="">— saved —</option>'
        + names.map((n) => `<option value="${n}">${n}</option>`).join('');
}

function loadLayoutPrefs() {
    try {
        const raw = localStorage.getItem(LAYOUT_PREFS_KEY);
        if (!raw) return;
        const data = JSON.parse(raw);
        if (Array.isArray(data.pins)) layoutState.pins = new Set(data.pins);
        if (typeof data.focusId === 'string') layoutState.focusId = data.focusId;
        if (data.focusSize === 'medium' || data.focusSize === 'large') {
            layoutState.focusSize = data.focusSize;
        }
        if (typeof data.filterText === 'string') layoutState.filterText = data.filterText;
        if (Array.isArray(data.filterChips)) {
            layoutState.filterChips = new Set(data.filterChips);
        }
        if (data.groupBy === 'role' || data.groupBy === 'project') {
            layoutState.groupBy = data.groupBy;
        }
        if (data.layoutMode === 'tiled' || data.layoutMode === 'stack' || data.layoutMode === 'carousel') {
            layoutState.layoutMode = data.layoutMode;
        }
        if (data.sortMode === 'name' || data.sortMode === 'recent') {
            layoutState.sortMode = data.sortMode;
        }
    } catch (_) { /* malformed prefs — drop */ }
}

function setupFilterBar() {
    const input = document.getElementById('filter-input');
    if (input) {
        input.value = layoutState.filterText || '';
        input.addEventListener('input', () => {
            layoutState.filterText = input.value;
            saveLayoutPrefs();

