function setupFilterBar() {
    const input = document.getElementById('filter-input');
    if (input) {
        input.value = layoutState.filterText || '';
        input.addEventListener('input', () => {
            layoutState.filterText = input.value;
            saveLayoutPrefs();
            const dashboard = document.getElementById('dashboard');
            if (dashboard && layoutState.enabled) {
                applyLayout(computeLayout(dashboard));
            }
        });
    }
    document.querySelectorAll('.filter-bar .chip[data-chip]').forEach((c) => {
        const chip = c.getAttribute('data-chip');
        c.classList.toggle('active', layoutState.filterChips.has(chip));
        c.addEventListener('click', () => {
            if (layoutState.filterChips.has(chip)) {
                layoutState.filterChips.delete(chip);
            } else {
                layoutState.filterChips.add(chip);
            }
            c.classList.toggle('active', layoutState.filterChips.has(chip));
            saveLayoutPrefs();
            const dashboard = document.getElementById('dashboard');
            if (dashboard && layoutState.enabled) {
                applyLayout(computeLayout(dashboard));
            }
        });
    });
    const gSel = document.getElementById('group-by');
    if (gSel) {
        gSel.value = layoutState.groupBy || '';
        gSel.addEventListener('change', () => {
            layoutState.groupBy = gSel.value;
            saveLayoutPrefs();
            const dashboard = document.getElementById('dashboard');
            if (dashboard && layoutState.enabled) {
                applyLayout(computeLayout(dashboard));
            }
        });
    }
    const saveBtn = document.getElementById('layout-save');
    if (saveBtn) saveBtn.addEventListener('click', () => {
        const name = prompt('Name this layout:');
        if (name) saveNamedLayout(name);
    });
    const applyBtn = document.getElementById('layout-apply');
    if (applyBtn) applyBtn.addEventListener('click', () => {
        const sel = document.getElementById('saved-layouts');
        if (sel && sel.value) applyNamedLayout(sel.value);
    });
    const delBtn = document.getElementById('layout-delete');
    if (delBtn) delBtn.addEventListener('click', () => {
        const sel = document.getElementById('saved-layouts');
        if (sel && sel.value) deleteNamedLayout(sel.value);
    });
    const refreshBtn = document.getElementById('btn-refresh-layout');
    if (refreshBtn) refreshBtn.addEventListener('click', () => {
        const dashboard = document.getElementById('dashboard');
        if (!dashboard || !layoutState.enabled) return;
        atnDebug.log('refresh:manual', {});
        applyLayout(computeLayout(dashboard));
        _lastAppliedHeat = new Map(layoutState.smoothed);
        refreshBtn.textContent = '↻ Refreshed';
        setTimeout(() => { refreshBtn.textContent = '↻ Refresh'; }, 800);
    });
}

function syncPinButtons() {
    document.querySelectorAll('.btn-pin[data-pin-id]').forEach((btn) => {
        const id = btn.getAttribute('data-pin-id');
        btn.classList.toggle('pinned', layoutState.pins.has(id));
        btn.title = layoutState.pins.has(id) ? 'Unpin' : 'Pin to always-visible row';
    });
}

