function renderWindowDock(minimized) {
    const dock = document.getElementById('window-dock');
    if (!dock) return;
    dock.classList.toggle('visible', minimized.length > 0);
    dock.innerHTML = '';
    for (const item of minimized) {
        const a = agents.get(item.id);
        if (!a) continue;
        const info = a.info || {};
        const stateObj = info.state || { state: 'idle' };
        const sk = stateKey(stateObj);
        const nameTxt = a.panel?.querySelector?.('.agent-name')?.textContent || item.id;
        const roleTxt = a.panel?.querySelector?.('.agent-role')?.textContent || '';
        const lastLine = a.lastLine || '';
        const cell = document.createElement('div');
        cell.className = 'dock-cell';
        cell.dataset.windowId = item.id;
        cell.title = `Restore ${nameTxt}`;
        cell.innerHTML = `
            <div class="dock-head">
                <span class="dock-name">${escapeHTML(nameTxt)}</span>
                <span class="dock-role">${escapeHTML(roleTxt)}</span>
                <span class="state-badge state-${sk} dock-state">${stateLabel(stateObj)}</span>
            </div>
            <div class="dock-last">${escapeHTML(lastLine) || '&nbsp;'}</div>
        `;
        dock.appendChild(cell);
    }
}

function escapeHTML(s) {
    return String(s == null ? '' : s)
        .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

function syncPinFilteredLabels() {
    document.querySelectorAll('.pin-cell[data-agent-id]').forEach((cell) => {
        const id = cell.getAttribute('data-agent-id');
        cell.classList.toggle('filtered', !matchesFilter(id));
    });
}

function refreshPinCell(agentId) {
    const cell = document.querySelector(`.pin-cell[data-agent-id="${agentId}"]`);
    if (!cell) return;
    const a = agents.get(agentId);
    if (!a) return;
    const path = cell.querySelector(`#pin-spark-${agentId}`);
    if (path) path.setAttribute('d', sparklinePath(a.heatRing, 44, 14));
    const ll = cell.querySelector(`#pin-lastline-${agentId}`);
    if (ll) ll.textContent = a.lastLine || ' ';
}

function updateSmoothedHeat(agentId, rawHeat) {
    const prev = layoutState.smoothed.get(agentId) ?? rawHeat;
    const next = prev * (1 - HEAT_SMOOTH_ALPHA) + rawHeat * HEAT_SMOOTH_ALPHA;
    layoutState.smoothed.set(agentId, next);
    return next;
}

function autoPickFocus(items) {
    if (items.length === 0) return null;
    // Prefer the highest-heat coordinator if there is one.
    let bestCoord = null, bestCoordV = -1;
    let bestAny = items[0];
    for (const it of items) {
        if (it.value > bestAny.value) bestAny = it;
        const a = agents.get(it.id);
        const role = a?.role || (a?.panel?.querySelector?.('.agent-role')?.textContent) || '';
        if (role.toLowerCase() === 'coordinator' && it.value > bestCoordV) {
            bestCoord = it;
            bestCoordV = it.value;
        }
    }
    return (bestCoord || bestAny).id;
}

function roleOf(id) {
    const a = agents.get(id);
    return (a?.info?.role
        || a?.panel?.querySelector?.('.agent-role')?.textContent
        || '').toLowerCase();
}

