function enableTreemapMode() {
    const dashboard = document.getElementById('dashboard');
    if (!dashboard) return;
    dashboard.classList.add('treemap-mode');
    dashboard.classList.remove('cols-1', 'cols-2', 'cols-3', 'cols-4');
    layoutState.enabled = true;
    applyLayout(computeLayout(dashboard));
}

const STATE_LABELS = {
    starting: 'Starting',
    running: 'Running',
    idle: 'Idle',
    awaiting_human_input: 'Awaiting Input',
    busy: 'Busy',
    blocked: 'Blocked',
    completed_task: 'Completed',
    error: 'Error',
    disconnected: 'Disconnected',
};

function stateKey(stateObj) {
    if (typeof stateObj === 'string') return stateObj;
    if (stateObj && stateObj.state) return stateObj.state;
    return 'starting';
}

function stateLabel(stateObj) {
    const key = stateKey(stateObj);
    return STATE_LABELS[key] || key;
}

