        setupControls(agent.id);
    }

    // Fetch per-agent saga step for badges
    pollAgentSagas(agentList.map(a => a.id));

    // Resize handling. xterm stays at fixed native geometry; the
    // treemap recomputes on window resize and per-tick, and
    // updateTileScales follows up to pick scale snap points.
    const onResize = () => {
        if (layoutState.enabled) {
            const db = document.getElementById('dashboard');
            if (db) applyLayout(computeLayout(db));
        }
        updateTileScales();
    };
    window.addEventListener('resize', onResize);
    new ResizeObserver(onResize).observe(dashboard);

    // Poll states
    setInterval(pollStates, 2000);

    // Start heat polling; feeds smoothedHeat for the treemap.
    startHeatPolling();

    // Hydrate user prefs (pins + focus + focus size + filter +
    // group-by) before the first layout so they're honored on the
    // very first render.
    loadLayoutPrefs();
    renderPinRow();
    syncPinButtons();

    // Wire the filter bar.
    setupFilterBar();
    refreshSavedLayoutsDropdown();

    // Show the filter bar once at least one agent exists.
    const fbar = document.getElementById('filter-bar');
    if (fbar && agentList.length > 0) fbar.classList.add('visible');

    // Flip the dashboard into treemap mode whenever at least one
    // agent is present (empty-state stays as the CTA card).
    if (agentList.length > 0) {
        enableTreemapMode();
    }

    // Treemap layout is explicit-refresh only — the ↻ Refresh
    // button in the filter bar recomputes on demand. Implicit
    // re-layouts still fire on agent create/delete/focus-swap
    // and on window / ResizeObserver resize so the dashboard
    // stays usable; only the timer-driven drift is gone.
    //
    // Use `atnDebug.trace()` in devtools to log every layout
    // event as it fires.

    // Expose dev toggles on window for devtools poking.
    window.toggleCompactMode = toggleCompactMode;
    window.setFocus = setFocus;
    window.pickTermScale = pickTermScale;
    window.layoutState = layoutState;
    window.squarify = squarify;
    window.enableTreemapMode = enableTreemapMode;
    window.togglePin = togglePin;
    window.saveLayoutPrefs = saveLayoutPrefs;
    window.atnDebug = atnDebug;
}

