// centered, every other window is implicitly dock-minimized
// for the duration (without mutating their stored state).
if (maxed) {
    const maxW = Math.floor(rect.w * 0.8);
    const maxH = Math.floor(rect.h * 0.9);
    const maxRect = {
        id: maxed.id,
        x: rect.x + Math.floor((rect.w - maxW) / 2),
        y: rect.y + Math.floor((rect.h - maxH) / 2),
        w: maxW, h: maxH,
    };
    const implicitDock = all.filter((it) => it.id !== maxed.id);
    return { windows: [maxRect], minimized: implicitDock };
}

// Otherwise lay out normal-state agents (dock minimized separately).
