// Stack mode: one primary window at ~80% viewport + everything
// else in the bottom dock. Primary = selected (if any) → coord
// → first in sort order. Stored window state is also kept in
// sync on mode transitions so a refresh renders the same way.
if (layoutState.layoutMode === 'stack') {
