function buildLayoutItems() {
    // Name-sorted, non-pinned, non-filtered agents. Coord promotion
    // is done inside computeLayout so the sort is a stable default
    // without special-casing here.
    const ids = Array.from(agents.keys())
        .filter((id) => !layoutState.pins.has(id) && matchesFilter(id));
    ids.sort((a, b) => a.localeCompare(b));
    return ids.map((id) => ({ id }));
}

// Stack-mode helpers.
//
// Stack mode keeps exactly one window "primary" (state = normal)
// and dock-minimizes the rest. Primary preference: whatever is
// currently `state:normal` in storage → selectedId → coord → first.
function pickStackPrimary(all) {
    if (!all || all.length === 0) return null;
    const normal = all.find((it) => windowState(it.id) === 'normal');
    if (normal) return normal.id;
    if (layoutState.selectedId
        && all.some((it) => it.id === layoutState.selectedId)) {
        return layoutState.selectedId;
    }
    const coord = all.find((it) => roleOf(it.id) === 'coordinator');
    if (coord) return coord.id;
    return all[0].id;
}

function enterStackMode() {
    // Reconcile stored state: one normal + rest minimized.
    const all = buildLayoutItems();
    if (all.length === 0) return;
    let primaryId = null;
    if (layoutState.selectedId
        && all.some((it) => it.id === layoutState.selectedId)) {
        primaryId = layoutState.selectedId;
    } else {
        const coord = all.find((it) => roleOf(it.id) === 'coordinator');
        primaryId = coord ? coord.id : all[0].id;
    }
    for (const it of all) {
        ensureWindow(it.id).state = (it.id === primaryId) ? 'normal' : 'minimized';
    }
    layoutState.selectedId = primaryId;
}

function leaveStackMode() {
    // Restore every non-pinned window to normal on exit.
    const all = buildLayoutItems();
    for (const it of all) {
        ensureWindow(it.id).state = 'normal';
    }
}

function stackPromote(id) {
    // Clicked dock cell becomes primary; previous primary minimizes.
    const all = buildLayoutItems();
    for (const it of all) {
        ensureWindow(it.id).state = (it.id === id) ? 'normal' : 'minimized';
    }
    layoutState.selectedId = id;
    saveLayoutPrefs();
    applyLayoutFresh();
}

function setLayoutMode(mode) {
    if (mode !== 'tiled' && mode !== 'stack') return;
    const prev = layoutState.layoutMode;
    if (prev === mode) return;
    if (mode === 'stack') {
        enterStackMode();
    } else if (prev === 'stack') {
        leaveStackMode();
    }
    layoutState.layoutMode = mode;
    saveLayoutPrefs();
    updateLayoutSelector();
    applyLayoutFresh();
}

function updateLayoutSelector() {
    document.querySelectorAll('.layout-btn[data-layout]').forEach((btn) => {
        btn.classList.toggle('active', btn.dataset.layout === layoutState.layoutMode);
    });
}

function setupLayoutSelector() {
    document.querySelectorAll('.layout-btn[data-layout]').forEach((btn) => {
        btn.addEventListener('click', () => setLayoutMode(btn.dataset.layout));
    });
    updateLayoutSelector();
}

