function addAgentPanel(agent) {
    const dashboard = document.getElementById('dashboard');
    const panel = createAgentPanel(agent);
    dashboard.appendChild(panel);

    const { term, fitAddon, nativeW, nativeH } = initTerminal(agent.id);
    agents.set(agent.id, { term, fitAddon, panel, evtSource: null, nativeW, nativeH });
    connectSSE(agent.id);
    setupControls(agent.id);
    refreshDashboardLayout();
    // If this is the first agent, flip to treemap mode + reveal
    // the filter bar. Otherwise the running refresh tick will
    // place the new tile within 1.5s.
    const fbar = document.getElementById('filter-bar');
    if (fbar) fbar.classList.add('visible');
    if (!layoutState.enabled) {
        enableTreemapMode();
    } else {
        applyLayout(computeLayout(dashboard));
    }
}

function refreshDashboardLayout() {
    const dashboard = document.getElementById('dashboard');
    const count = dashboard.querySelectorAll('.agent-panel').length;
    document.getElementById('agent-count').textContent = `${count} agent${count !== 1 ? 's' : ''}`;
    if (count <= 1) dashboard.className = 'dashboard cols-1';
    else if (count <= 2) dashboard.className = 'dashboard cols-2';
    else if (count <= 3) dashboard.className = 'dashboard cols-3';
    else dashboard.className = 'dashboard cols-4';
    // Grid columns changed — CSS scale needs to catch up. No fit,
    // no PTY resize (that's setFocus's job).
    updateTileScales();
}

function toggleConfig(agentId) {
    const editor = document.getElementById(`cfg-${agentId}`);
    if (!editor) return;
    if (!editor.classList.contains('visible')) {
        // Build fresh markup from the latest AgentInfo. Using innerHTML
        // keeps state simple: every open starts from the current spec.
        renderConfigEditor(editor, agentId);
    }

