(async () => {
  // Wait for at least one agent panel to appear.
  const deadline = Date.now() + 4000;
  while (Date.now() < deadline) {
    if (document.querySelectorAll('.agent-panel').length >= 3) break;
    await new Promise(r => setTimeout(r, 100));
  }
  const agentCount = document.querySelectorAll('.agent-panel').length;
  const sel = document.getElementById('layout-selector');
  const active = document.querySelector('.layout-btn.active')?.dataset.layout;
  const mode = window.layoutState?.layoutMode;
  return { agentCount, selectorExists: !!sel, active, mode };
})();

