(() => {
  const ls = window.layoutState;
  const windows = ls.windows;
  const counts = { normal: 0, minimized: 0, maximized: 0 };
  for (const id of Object.keys(windows)) counts[windows[id].state]++;
  // Which panel is visible at >500px wide? Should be the primary.
  const panels = Array.from(document.querySelectorAll('.agent-panel'));
  const big = panels.filter(p => p.offsetWidth > 500).map(p => p.id);
  const offscreen = panels.filter(p => p.style.left === '-9999px').map(p => p.id);
  const dockVisible = document.getElementById('window-dock').classList.contains('visible');
  const dockCells = Array.from(document.querySelectorAll('.dock-cell')).map(c => c.dataset.windowId);
  const active = document.querySelector('.layout-btn.active')?.dataset.layout;
  return {
    mode: ls.layoutMode,
    active,
    selectedId: ls.selectedId,
    windows,
    counts,
    big,
    offscreen,
    dockVisible,
    dockCells,
  };
})();

