    const sk = stateKey(agent.state);
    tile.innerHTML = `
        <div class="compact-head">
            <span class="compact-name">${agent.name}</span>
            <span class="compact-role">${agent.role}</span>
            <span class="compact-spacer"></span>
            <span class="state-badge state-${sk}" id="compact-badge-${agent.id}">${stateLabel(agent.state)}</span>
        </div>
        <div class="compact-body">
            <svg class="sparkline" viewBox="0 0 60 18" preserveAspectRatio="none">
                <path d="" id="compact-spark-${agent.id}"></path>
            </svg>
            <span class="last-line" id="compact-lastline-${agent.id}">&nbsp;</span>
            <span class="focus-hint">click to focus ▸</span>
        </div>
    `;
    tile.addEventListener('click', () => {
        const evt = new CustomEvent('swap-to-focus', {
            detail: { agentId: agent.id },
            bubbles: true,
        });
        tile.dispatchEvent(evt);
    });
    return tile;
}

function refreshCompactIfPresent(agentId) {
    const tile = document.getElementById(`compact-${agentId}`);
    if (tile) {
        const a = agents.get(agentId);
        if (a) {
            const pathEl = tile.querySelector(`#compact-spark-${agentId}`);
            if (pathEl) pathEl.setAttribute('d', sparklinePath(a.heatRing, 60, 18));
            const lastEl = tile.querySelector(`#compact-lastline-${agentId}`);
            if (lastEl) lastEl.textContent = a.lastLine || ' ';
        }
    }
    // Pin cells show the same live data when the agent is pinned.
    if (typeof refreshPinCell === 'function') refreshPinCell(agentId);
}

// Manual toggle for developer testing before step 4 picks the mode
// by tile size. Swaps a full panel in/out for its compact tile.
function toggleCompactMode(agentId) {
    const a = agents.get(agentId);
    if (!a) return;
    const current = document.getElementById(`panel-${agentId}`)
        || document.getElementById(`compact-${agentId}`);
    if (!current) return;
    const dashboard = document.getElementById('dashboard');
    if (a.mode === 'xterm') {
        const compact = createCompactTile({
            id: agentId,
            name: a.panel?.querySelector('.agent-name')?.textContent || agentId,
            role: a.panel?.querySelector('.agent-role')?.textContent || 'agent',
            state: { state: 'idle' },
        });
        dashboard.replaceChild(compact, current);
        a.mode = 'compact';
        refreshCompactIfPresent(agentId);

