// swap-to-focus: promote the clicked tile to the focus panel.
// Freezes layout refreshes for a moment so the user's click
// isn't immediately overwritten by the heat poll's re-layout.
document.addEventListener('swap-to-focus', (e) => {
    const id = e.detail && e.detail.agentId;
    if (!id || !agents.has(id)) return;
    layoutState.focusId = id;
    layoutState.freezeUntil = Date.now() + LAYOUT_FREEZE_MS;
    saveLayoutPrefs();
    const dashboard = document.getElementById('dashboard');
    if (dashboard && layoutState.enabled) {
        applyLayout(computeLayout(dashboard));
    }
    // setFocus handles the PTY-resize + xterm fit so the focused
    // tile is crisp at its new geometry.
    setFocus(id);
});

