/**
 * Promote an agent to the focus slot. Only the focus tile gets a
 * real fit-addon resize + PTY size sync. Step 4 will drive this
 * from click events.
 */
let currentFocusId = null;
function setFocus(agentId) {
    currentFocusId = agentId;
    const a = agents.get(agentId);
    if (!a || !a.fitAddon) return;
    // Reset this tile's scale and fit xterm to its container.
    const scaleEl = document.getElementById(`term-scale-${agentId}`);
    if (scaleEl) scaleEl.style.setProperty('--term-k', '1');
    try {
        a.fitAddon.fit();
        syncPtySize(agentId, a.term);
    } catch (_) { /* xterm not rendered yet; next call will work */ }
    updateTileScales();
}

// --- pickTermScale self-test ---
//
// No JS test framework in the project, so the test runs on load
// and logs PASS/FAIL to the console. Touchpoints: result values,
// below-threshold → null, degenerate dims → null.
(function testPickTermScale() {
    const cases = [
        { in: [960, 680, 960, 680], want: 1.0, desc: 'exact native fit' },
        { in: [480, 340, 960, 680], want: 0.5, desc: 'half-scale tile' },
