function setLayoutMode(mode) {
    if (mode !== 'tiled' && mode !== 'stack' && mode !== 'carousel') return;
    const prev = layoutState.layoutMode;
    if (prev === mode) return;
    // Leaving stack restores minimized windows to normal so the
    // next mode doesn't see lingering stack state.
    if (prev === 'stack' && mode !== 'stack') {
        leaveStackMode();
    }
    // Entering stack reconciles to one-primary-plus-minimized.
    if (mode === 'stack') {
        enterStackMode();
    }
    // Maximized is a tiled-mode affordance; short-circuiting it on a
    // mode change keeps the stack/carousel math uncomplicated. We
    // preserve user-driven minimized state so dock survives the switch.
    for (const id of Object.keys(layoutState.windows)) {
        if (layoutState.windows[id].state === 'maximized') {
            layoutState.windows[id].state = 'normal';
        }
    }
    layoutState.layoutMode = mode;
    saveLayoutPrefs();
    updateLayoutSelector();
    updateCarouselNav();
    applyLayoutFresh();
}

function updateLayoutSelector() {
    document.querySelectorAll('.layout-btn[data-layout]').forEach((btn) => {
