    if (eligible.length === 0) return;
    let idx = -1;
    if (layoutState.selectedId) {
        idx = eligible.findIndex((it) => it.id === layoutState.selectedId);
    }
    if (idx < 0) {
        const coord = eligible.findIndex((it) => roleOf(it.id) === 'coordinator');
        idx = coord >= 0 ? coord : 0;
    }
    const n = eligible.length;
    const nextIdx = ((idx + delta) % n + n) % n;
    layoutState.selectedId = eligible[nextIdx].id;
    saveLayoutPrefs();
    applyLayoutFresh();
}

