(() => {
  // Inspect the three agent tiles' positions + sizes so we know which
  // is primary vs peek.
  const vw = window.innerWidth;
  const tiles = Array.from(document.querySelectorAll('.agent-panel, .agent-compact'))
    .filter(el => el.style.left !== '-9999px' && el.offsetWidth > 0)
    .map(el => {
      const id = el.id.replace(/^(panel|compact)-/, '');
      return {
        id,
        tag: el.classList.contains('agent-compact') ? 'compact' : 'xterm',
        x: parseInt(el.style.left, 10) || 0,
        w: el.offsetWidth,
      };
    })
    .sort((a, b) => a.x - b.x);
  return {
    mode: window.layoutState.layoutMode,
    selectedId: window.layoutState.selectedId,
    navVisible: document.getElementById('carousel-nav').classList.contains('visible'),
    active: document.querySelector('.layout-btn.active')?.dataset.layout,
    tiles,
    viewportW: vw,
  };
})();

