(() => {
  // Manually minimize worker-hlasm via the existing window chrome.
  window.windowMinimize('worker-hlasm');
  const dockCells = Array.from(document.querySelectorAll('.dock-cell'))
    .map(c => c.dataset.windowId);
  // Now cycle forward twice — should visit worker-rpg → coordinator, skipping worker-hlasm.
  const seen = [];
  const initial = window.layoutState.selectedId;
  seen.push(initial);
  window.carouselCycle(1);
  seen.push(window.layoutState.selectedId);
  window.carouselCycle(1);
  seen.push(window.layoutState.selectedId);
  window.carouselCycle(1);
  seen.push(window.layoutState.selectedId);
  return {
    dockCells,
    cycleTrail: seen,
    mode: window.layoutState.layoutMode,
  };
})();

