function syncPinButtons() {
    document.querySelectorAll('.btn-pin[data-pin-id]').forEach((btn) => {
        const id = btn.getAttribute('data-pin-id');
        btn.classList.toggle('pinned', layoutState.pins.has(id));
        btn.title = layoutState.pins.has(id) ? 'Unpin' : 'Pin to always-visible row';
    });
}

function togglePin(agentId) {
    if (layoutState.pins.has(agentId)) {
        layoutState.pins.delete(agentId);
    } else {
        if (layoutState.pins.size >= PINS_MAX) {
            console.warn(`pin limit reached (${PINS_MAX}); unpin something first`);
            return;
        }
        layoutState.pins.add(agentId);
        // Pinning the current focus gives focus back to auto-pick.
        if (layoutState.focusId === agentId) {
            layoutState.focusId = null;
        }
    }
    saveLayoutPrefs();
    renderPinRow();
    syncPinButtons();
    const dashboard = document.getElementById('dashboard');
    if (dashboard && layoutState.enabled) {
        applyLayout(computeLayout(dashboard));
    }
}

function renderPinRow() {
    const row = document.getElementById('pin-row');
    if (!row) return;
    row.innerHTML = '';
    const anyPins = layoutState.pins.size > 0;
    row.classList.toggle('visible', anyPins);
    for (const id of layoutState.pins) {
        if (!agents.has(id)) continue;
        const cell = document.createElement('div');
        cell.className = 'pin-cell';
        cell.dataset.agentId = id;
        const a = agents.get(id);
        const name = a?.panel?.querySelector?.('.agent-name')?.textContent || id;
        const role = a?.panel?.querySelector?.('.agent-role')?.textContent || 'agent';
        const stateLabelTxt = a?.panel?.querySelector?.('.state-badge')?.textContent || 'Idle';
        const stateCls = a?.panel?.querySelector?.('.state-badge')?.className || 'state-badge state-idle';
        cell.innerHTML = `
            <button class="pin-unpin" title="Unpin" data-unpin-id="${id}">×</button>
            <div class="pin-head">
                <span class="pin-icon">📌</span>
                <span class="pin-name" title="${name}">${name}</span>
                <span class="${stateCls} pin-state">${stateLabelTxt}</span>
            </div>
            <div class="pin-body">
                <svg class="sparkline" viewBox="0 0 44 14" preserveAspectRatio="none">
                    <path d="" id="pin-spark-${id}"></path>
                </svg>
                <span class="pin-lastline" id="pin-lastline-${id}">&nbsp;</span>
            </div>
        `;
        cell.addEventListener('click', (e) => {
            // Clicking the × unpins; clicking elsewhere focuses.
            if (e.target.closest('[data-unpin-id]')) {
                togglePin(id);
                e.stopPropagation();
                return;
            }
            document.dispatchEvent(new CustomEvent('swap-to-focus', {
                detail: { agentId: id },
            }));
        });
        row.appendChild(cell);
        // Seed sparkline + last-line from current state.
        const path = cell.querySelector(`#pin-spark-${id}`);
        if (path) path.setAttribute('d', sparklinePath(a.heatRing, 44, 14));
        const ll = cell.querySelector(`#pin-lastline-${id}`);
        if (ll) ll.textContent = a.lastLine || ' ';
    }
}

