        el.style.width = `${rect.w}px`;
        el.style.height = `${rect.h}px`;
        if (el.classList.contains('agent-panel')) {
            el.classList.remove('focus');
        }
    };
    // Move any not-in-layout panels off-screen (pinned agents,
    // filter misses, minimized agents — the dock shows those).
    const visibleIds = new Set(windows.map(w => w.id));
    for (const id of agents.keys()) {
        if (layoutState.pins.has(id)) continue;
        if (visibleIds.has(id)) continue;
        const el = document.getElementById(`panel-${id}`)
            || document.getElementById(`compact-${id}`);
        if (el) {
            el.style.left = '-9999px';
            el.style.top = '-9999px';
            el.style.width = '0';
            el.style.height = '0';
        }
    }
    for (const w of windows) {
        ensureModeFor(w.id, w);
        place(w.id, w);
    }
    // Selected outline follows state.
    document.querySelectorAll('.agent-panel.selected').forEach(el => el.classList.remove('selected'));
    if (layoutState.selectedId) {
        const sel = document.getElementById(`panel-${layoutState.selectedId}`);
        if (sel) {
            sel.classList.add('selected');
            // Selected non-minimized tile gets full xterm fit.
            fitSelectedTerm(layoutState.selectedId);
        }
    }
    // Step 1 has no group bands; clear any that may have been left
    // over from a stale layout.
    dashboard.querySelectorAll('.group-band').forEach((b) => b.remove());
    renderWindowDock(minimized);
    // Refresh the pin row so (filtered) labels update.
    syncPinFilteredLabels();
    // After positions change, update per-xterm scales.
    updateTileScales();
}

