/* Sparkline row — always-visible strip above the dashboard with one
   cell per agent (flex 1/n). Click to focus. The pinned 📌 icon in
   a cell indicates that window is locked-in-place on the dashboard. */
.sparkline-row { display: none; gap: 6px; padding: 6px 8px; border-bottom: 1px solid #0f3460; background: #16213e; flex-shrink: 0; }
.sparkline-row.visible { display: flex; }
.spark-cell { flex: 1 1 0; min-width: 80px; height: 56px; border: 1px solid #0f3460; border-radius: 6px; background: #0d1117; padding: 4px 8px; cursor: pointer; display: flex; flex-direction: column; gap: 2px; overflow: hidden; position: relative; }
.spark-cell:hover { border-color: #4ecca3; }
.spark-cell.selected { border-color: #4ecca3; }
.spark-cell.pinned { border-color: #fbbf24; }
.spark-cell .sc-head { display: flex; align-items: center; gap: 4px; font-size: 11px; min-width: 0; }
.spark-cell .sc-pin { color: #fbbf24; font-size: 10px; flex-shrink: 0; }
.spark-cell .sc-name { font-weight: 600; color: #c9d1d9; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; flex: 1; min-width: 0; }
.spark-cell .sc-role { font-size: 9px; color: #888; text-transform: uppercase; flex-shrink: 0; }
.spark-cell .sc-state { font-size: 9px; padding: 1px 4px; }
.spark-cell .sc-body { display: flex; align-items: center; gap: 4px; min-width: 0; flex: 1; }
.spark-cell .sparkline { flex-shrink: 0; width: 48px; height: 16px; }
.spark-cell .sparkline path { fill: none; stroke: #4ecca3; stroke-width: 1.5; }
.spark-cell .sc-last { flex: 1; min-width: 0; font-family: monospace; font-size: 9px; color: #6b7280; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

/* Pinned (locked-in-place) windows float above normal tiles and
   carry a subtle amber outline so they stand out. */
.dashboard .agent-panel.pinned,
.dashboard .agent-compact.pinned { outline: 2px solid #fbbf24; outline-offset: -2px; z-index: 10; }

/* Carousel ◀/▶ cycle buttons — only shown when Carousel mode is active. */

