// Move any not-in-layout panels off-screen (filter misses,
// minimized agents — the dock shows those). Pinned windows
// are placed below at their stored rect.
const visibleIds = new Set(windows.map(w => w.id));
const pinnedIds = new Set(layoutState.pins);
for (const id of agents.keys()) {
    if (visibleIds.has(id) || pinnedIds.has(id)) continue;
    const el = document.getElementById(`panel-${id}`)
        || document.getElementById(`compact-${id}`);
    if (el) {
        el.style.left = '-9999px';
        el.style.top = '-9999px';
        el.style.width = '0';
        el.style.height = '0';
        el.classList.remove('pinned');
        el.style.zIndex = '';
    }
}
for (const w of windows) {
    // Pinned overrides come below; skip placing here so we
    // don't double-position if the same id appears in both.
    if (pinnedIds.has(w.id)) continue;
    ensureModeFor(w.id, w);
    place(w.id, w);
    const el = document.getElementById(`panel-${w.id}`)
        || document.getElementById(`compact-${w.id}`);
    if (el) {
        el.classList.remove('pinned');
        el.style.zIndex = '';
    }
}
// Pinned = locked in place. Place at the stored rect, above
// normal tiles, regardless of which mode is active.
for (const id of pinnedIds) {
    if (!agents.has(id)) continue;
    const wdef = layoutState.windows[id];
    const pr = wdef && wdef.pinnedRect;
    if (!pr) continue;
    const rect = { id, x: pr.x, y: pr.y, w: pr.w, h: pr.h };
    ensureModeFor(id, rect);
    place(id, rect);
    const el = document.getElementById(`panel-${id}`)
        || document.getElementById(`compact-${id}`);
    if (el) {
        el.classList.add('pinned');
        el.style.zIndex = '10';
