function loadLayoutPrefs() {
    try {
        const raw = localStorage.getItem(LAYOUT_PREFS_KEY);
        if (!raw) return;
        const data = JSON.parse(raw);
        if (Array.isArray(data.pins)) layoutState.pins = new Set(data.pins);
        if (typeof data.focusId === 'string') layoutState.focusId = data.focusId;
        if (data.focusSize === 'medium' || data.focusSize === 'large') {
            layoutState.focusSize = data.focusSize;
        }
        if (typeof data.filterText === 'string') layoutState.filterText = data.filterText;
        if (Array.isArray(data.filterChips)) {
            layoutState.filterChips = new Set(data.filterChips);
        }
        if (data.groupBy === 'role' || data.groupBy === 'project') {
            layoutState.groupBy = data.groupBy;
        }
        if (data.layoutMode === 'tiled' || data.layoutMode === 'stack' || data.layoutMode === 'carousel') {
            layoutState.layoutMode = data.layoutMode;
        }
        if (data.sortMode === 'name' || data.sortMode === 'recent') {
            layoutState.sortMode = data.sortMode;
        }
    } catch (_) { /* malformed prefs — drop */ }
}

function setupFilterBar() {
    const input = document.getElementById('filter-input');
    if (input) {
        input.value = layoutState.filterText || '';

