(() => {
  // Capture the tiled rect of coordinator before pinning.
  const beforeEl = document.getElementById('panel-coordinator');
  const before = {
    x: parseInt(beforeEl.style.left, 10) || 0,
    y: parseInt(beforeEl.style.top, 10) || 0,
    w: beforeEl.offsetWidth,
    h: beforeEl.offsetHeight,
  };
  // Pin coordinator.
  window.togglePin('coordinator');
  const afterPin = {
    pins: Array.from(window.layoutState.pins),
    pinnedRect: window.layoutState.windows['coordinator']?.pinnedRect,
    pinnedClass: document.getElementById('panel-coordinator')?.classList.contains('pinned'),
    sparkPinned: document.querySelector('.spark-cell[data-agent-id="coordinator"]')?.classList.contains('pinned'),
  };
  // Switch to Stack mode.
  window.setLayoutMode('stack');
  const afterStack = {
    mode: window.layoutState.layoutMode,
    coordStillAtPinRect: (() => {
      const el = document.getElementById('panel-coordinator');
      return {
        x: parseInt(el.style.left, 10) || 0,
        y: parseInt(el.style.top, 10) || 0,
        w: el.offsetWidth,
        h: el.offsetHeight,
        zIndex: el.style.zIndex,
        pinned: el.classList.contains('pinned'),
      };
    })(),
    // Stack should have picked someone else as primary (since coord is
    // pinned and excluded from the stack-layout pool).
    selected: window.layoutState.selectedId,
  };
  // Switch to Carousel.
  window.setLayoutMode('carousel');
  const afterCarousel = {
    mode: window.layoutState.layoutMode,
    coordCoords: (() => {
      const el = document.getElementById('panel-coordinator');
      return {
        x: parseInt(el.style.left, 10) || 0,
        y: parseInt(el.style.top, 10) || 0,
        w: el.offsetWidth,
        h: el.offsetHeight,
      };
    })(),
    selected: window.layoutState.selectedId,
  };
  return { before, afterPin, afterStack, afterCarousel };
})();

