function setupControls(agentId) {
    const input = document.getElementById(`input-${agentId}`);
    const panel = document.getElementById(`panel-${agentId}`);
    const sendBtn = panel.querySelector('.btn-send');
    const ctrlcBtn = panel.querySelector('.btn-ctrl-c');

    function doSend() {
        const text = input.value;
        if (text) {
            // Send text, then Enter as separate raw bytes after a
            // short delay so TUI apps exit bracketed paste mode first.
            fetch(`${API_BASE}/api/agents/${agentId}/input`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ text }),
            }).then(() => {
                setTimeout(() => {
                    sendRawBytes(agentId, [13]); // \r = Enter
                }, 100);
            });
            input.value = '';
        }
        input.focus();
    }

    function sendRawBytes(agentId, bytes) {
        fetch(`${API_BASE}/api/agents/${agentId}/input`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ raw_bytes: bytes }),
        });
    }

    sendBtn.addEventListener('click', doSend);
    input.addEventListener('keydown', (e) => {
        if (e.key === 'Enter') { e.preventDefault(); doSend(); }
        else if (e.key === 'ArrowUp') { e.preventDefault(); sendRawBytes(agentId, [27, 91, 65]); }
        else if (e.key === 'ArrowDown') { e.preventDefault(); sendRawBytes(agentId, [27, 91, 66]); }
        else if (e.key === 'ArrowRight') { e.preventDefault(); sendRawBytes(agentId, [27, 91, 67]); }
        else if (e.key === 'ArrowLeft') { e.preventDefault(); sendRawBytes(agentId, [27, 91, 68]); }
        else if (e.key === 'Tab') { e.preventDefault(); sendRawBytes(agentId, [9]); }
        else if (e.key === 'Escape') { e.preventDefault(); sendRawBytes(agentId, [27]); }
    });

    ctrlcBtn.addEventListener('click', () => {
        fetch(`${API_BASE}/api/agents/${agentId}/ctrl-c`, { method: 'POST' });
        input.focus();
    });

