(async () => {
  const deadline = Date.now() + 4000;
  while (Date.now() < deadline) {
    if (document.querySelectorAll('.agent-panel').length >= 3) break;
    await new Promise(r => setTimeout(r, 100));
  }
  // Intercept POST /api/agents/<id>/input requests to confirm Send fires.
  const hits = [];
  const origFetch = window.fetch;
  window.fetch = function(...args) {
    hits.push({ url: args[0], body: args[1]?.body });
    return origFetch.apply(this, args);
  };
  const input = document.getElementById('input-coordinator');
  input.value = 'pwd';
  const sendBtn = document.querySelector('.btn-send[data-agent="coordinator"]');
  sendBtn.click();
  // Wait a moment for network + SSE.
  await new Promise(r => setTimeout(r, 600));
  const xterm = document.querySelector('#term-coordinator .xterm-rows')?.textContent || '';
  return {
    hits: hits.filter(h => String(h.url).includes('/input')).map(h => ({ url: String(h.url), body: h.body })),
    xtermTail: xterm.slice(-200),
  };
})();

