function doSend() {
    const text = input.value;
    if (text) {
        // Send text + Enter as a single atomic POST. Splitting
        // them into two requests introduced a race: rapid typing
        // could queue a second text POST before the first Enter
        // landed, producing mashed output like "pwdpwdbash".
        fetch(`${API_BASE}/api/agents/${agentId}/input`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ text: text + '\r' }),
        });
        input.value = '';
    }
    input.focus();
}

