function buildLayoutItems() {
    // Name-sorted, non-pinned, non-filtered agents. Coord promotion
    // is done inside computeLayout so the sort is a stable default
    // without special-casing here.
    const ids = Array.from(agents.keys())
        .filter((id) => !layoutState.pins.has(id) && matchesFilter(id));
    ids.sort((a, b) => a.localeCompare(b));
    return ids.map((id) => ({ id }));
}

