/* Keyboard hint — muted text in the top bar listing the bare-key
   bindings. Visible at all times; step 6 may make it dismissible. */
.kbd-hint { font-size: 11px; color: #6b7280; margin-left: 8px; font-family: system-ui, sans-serif; }
.kbd-hint .kbd { color: #9ca3af; font-family: 'JetBrains Mono', monospace; }

/* PTY-focus badge — appears near the Send button when focus is
   inside that panel's xterm, signaling that keystrokes go to the
   PTY instead of to the window-management keyboard layer. */
.pty-focus-badge { display: none; font-size: 10px; color: #fbbf24; padding: 2px 6px; border: 1px solid #fbbf24; border-radius: 10px; margin-right: 4px; white-space: nowrap; }
.agent-panel.pty-focused .pty-focus-badge { display: inline-block; }

