// --- Keyboard shortcuts (Option C — click-to-select, no mode) ---
//
// Bindings fire only when no input/textarea/select/xterm has focus:
//   m       minimize selected
//   M       maximize / restore toggle on selected
//   p       pin / unpin selected (lock in place)
//   ← / →   cycle focus prev / next by sort order
//   1..9    jump to Nth window by sort order
//   /       focus the filter input (convenience)
//   Esc     deselect + restore any maximized window

function isTypingTarget(t) {
    if (!t) return false;
    const tag = (t.tagName || '').toLowerCase();
    if (tag === 'input' || tag === 'textarea' || tag === 'select') return true;
    if (t.isContentEditable) return true;
    if (t.closest && t.closest('.xterm')) return true;
    return false;
}

function isXtermFocused() {
    const el = document.activeElement;
    return !!(el && el.closest && el.closest('.xterm'));
}

function keyboardCycleItems() {
    // Sort-order list of focus candidates. Excludes minimized windows
    // (both regular and pinned-minimized) so cycling doesn't jump to
    // something invisible. Pinned-normal agents stay in the cycle.
    return Array.from(agents.keys())
        .filter((id) => matchesFilter(id) && windowState(id) !== 'minimized')
        .sort((a, b) => a.localeCompare(b));
}

function keyboardJump(n) {
    const items = keyboardCycleItems();
    if (items.length < n) return false;
    windowSelect(items[n - 1]);
    return true;
}

function keyboardCycle(delta) {
    const items = keyboardCycleItems();
    if (items.length === 0) return;
    let idx = items.indexOf(layoutState.selectedId);
    if (idx < 0) {
        // Nothing selected — land on the first (or last if going prev).
        idx = delta > 0 ? -1 : 0;
    }
    const next = ((idx + delta) % items.length + items.length) % items.length;
    windowSelect(items[next]);
}

document.addEventListener('keydown', (e) => {
    if (isTypingTarget(e.target)) return;
    if (isXtermFocused()) return;
    if (e.metaKey || e.ctrlKey || e.altKey) return;
    const k = e.key;
    const sel = layoutState.selectedId;

    if (k >= '1' && k <= '9') {
        if (keyboardJump(parseInt(k, 10))) e.preventDefault();
        return;
    }
    if (k === 'ArrowLeft') {
        e.preventDefault();
        keyboardCycle(-1);
        return;
    }
    if (k === 'ArrowRight') {
        e.preventDefault();
        keyboardCycle(1);
        return;
    }
    if (k === 'm') {
        if (sel && agents.has(sel)) {
            e.preventDefault();
            windowMinimize(sel);
        }
        return;
    }
    if (k === 'M') {
        if (sel && agents.has(sel)) {
            e.preventDefault();
            windowMaximizeToggle(sel);
        }
        return;
    }
    if (k === 'p') {
        if (sel && agents.has(sel)) {
            e.preventDefault();
            togglePin(sel);
        }
        return;
    }
    if (k === '/') {
        const input = document.getElementById('filter-input');
        if (input) {
            e.preventDefault();
            input.focus();
        }
        return;
    }
    if (k === 'Escape') {
        e.preventDefault();
        // Restore any maximized window first; second Esc deselects.
        const maxedId = hasMaximized();
        if (maxedId) {
            windowRestore(maxedId);
            return;
        }
        if (layoutState.selectedId !== null) {
            windowSelect(null);
        }
        return;
    }
});

// Track when focus lands inside a panel's xterm so the UI can flip
// the `pty-focused` class (which reveals the "typing to PTY" badge
// and signals that keys bypass the window-management layer).
document.addEventListener('focusin', (e) => {
    const panel = e.target && e.target.closest && e.target.closest('.agent-panel');
    const inXterm = e.target && e.target.closest && e.target.closest('.xterm');
    document.querySelectorAll('.agent-panel.pty-focused').forEach((p) => {
        if (p !== panel || !inXterm) p.classList.remove('pty-focused');
    });
    if (panel && inXterm) panel.classList.add('pty-focused');
});
document.addEventListener('focusout', (e) => {
    const panel = e.target && e.target.closest && e.target.closest('.agent-panel');
    if (!panel) return;
    // Defer so focus can settle on the next target before we clear.
    setTimeout(() => {
        const active = document.activeElement;
        if (!active || !active.closest || !active.closest('.xterm')) {
            panel.classList.remove('pty-focused');
        }
    }, 0);
});

