(async () => {
  const deadline = Date.now() + 4000;
  while (Date.now() < deadline) {
    if (document.querySelectorAll('.agent-panel').length >= 3) break;
    await new Promise(r => setTimeout(r, 100));
  }
  // Reset any persisted state for a clean start.
  try { localStorage.removeItem('atn-scale-ui-v1'); } catch(_) {}
  window.layoutState.pins = new Set();
  window.layoutState.layoutMode = 'tiled';
  window.layoutState.selectedId = null;
  window.layoutState.windows = {};
  if (window.updateLayoutSelector) window.updateLayoutSelector();
  if (window.renderSparklineRow) window.renderSparklineRow();
  window.applyLayoutFresh?.();
  // Verify hint + badge DOM present.
  return {
    hint: document.getElementById('kbd-hint')?.textContent?.slice(0, 80),
    badges: document.querySelectorAll('.pty-focus-badge').length,
    agents: document.querySelectorAll('.agent-panel').length,
  };
})();

