(async () => {
  // Dispatch synthetic keyboard events at document. They go through the
  // listener only if e.target is not a typing target — we can use body.
  const fire = (key) => {
    const e = new KeyboardEvent('keydown', { key, bubbles: true });
    document.body.dispatchEvent(e);
  };

  const out = {};

  // 1) Select coordinator via click on its header.
  document.querySelector('.agent-header[data-window-id="coordinator"]').click();
  out.selectedAfterClick = window.layoutState.selectedId;

  // 2) Press 'm' → minimize coordinator.
  fire('m');
  await new Promise(r => setTimeout(r, 50));
  out.afterM = {
    coordState: window.layoutState.windows['coordinator']?.state,
    selected: window.layoutState.selectedId,
    dock: Array.from(document.querySelectorAll('.dock-cell')).map(c => c.dataset.windowId),
  };

  // 3) Click worker-hlasm header, press 'M' → maximize.
  document.querySelector('.agent-header[data-window-id="worker-hlasm"]').click();
  fire('M');
  await new Promise(r => setTimeout(r, 50));
  out.afterShiftM = {
    hlasmState: window.layoutState.windows['worker-hlasm']?.state,
    hasMaxed: window.hasMaximized?.(),
    panelW: document.getElementById('panel-worker-hlasm')?.offsetWidth,
  };

  // 4) Press Esc → should restore maximized.
  fire('Escape');
  await new Promise(r => setTimeout(r, 50));
  out.afterEsc1 = {
    hasMaxed: window.hasMaximized?.(),
    selected: window.layoutState.selectedId,
  };

  // 5) Press Esc again → deselect.
  fire('Escape');
  await new Promise(r => setTimeout(r, 50));
  out.afterEsc2 = { selected: window.layoutState.selectedId };

  // 6) Press '2' → jump to 2nd window by sort order.
  // Sort order (after step 2 dock-restore): sort by name: coordinator, worker-hlasm, worker-rpg.
  // But coordinator is still minimized, so cycle list = [worker-hlasm, worker-rpg].
  // '1' = worker-hlasm, '2' = worker-rpg.
  fire('2');
  await new Promise(r => setTimeout(r, 50));
  out.after2 = { selected: window.layoutState.selectedId };

  // 7) Press '9' → no-op (only 2 items in cycle list).
  const before9 = window.layoutState.selectedId;
  fire('9');
  await new Promise(r => setTimeout(r, 50));
  out.after9 = { selected: window.layoutState.selectedId, changed: window.layoutState.selectedId !== before9 };

  // 8) Press '→' → cycle to next.
  fire('ArrowRight');
  await new Promise(r => setTimeout(r, 50));
  out.afterRight = { selected: window.layoutState.selectedId };

  fire('ArrowLeft');
  await new Promise(r => setTimeout(r, 50));
  out.afterLeft = { selected: window.layoutState.selectedId };

  // 9) Press 'p' → pin currently selected.
  const selForPin = window.layoutState.selectedId;
  fire('p');
  await new Promise(r => setTimeout(r, 50));
  out.afterP = {
    sel: selForPin,
    pinned: Array.from(window.layoutState.pins),
    pinnedRect: window.layoutState.windows[selForPin]?.pinnedRect,
  };

  // 10) Simulate xterm focus → keys should be ignored by our handler.
  const selBefore = window.layoutState.selectedId;
  const fakeXterm = document.querySelector('.xterm');
  if (fakeXterm) {
    // Use a textarea inside xterm (xterm.js uses a helper textarea for input).
    const ta = fakeXterm.querySelector('textarea') || fakeXterm;
    ta.focus();
  }
  // Dispatch 'm' directly on document — our handler checks activeElement via isXtermFocused().
  document.dispatchEvent(new KeyboardEvent('keydown', { key: 'm', bubbles: true }));
  await new Promise(r => setTimeout(r, 50));
  out.xtermGuard = {
    activeInXterm: !!(document.activeElement?.closest('.xterm')),
    selectionUnchanged: window.layoutState.selectedId === selBefore,
    someoneStateChanged: window.layoutState.windows[selBefore]?.state === 'minimized',
  };

  return out;
})();

