 *  are not auto-included here — callers decide whether to override
 *  (pin row shows pinned regardless; treemap does not). */
function matchesFilter(agentId) {
    const entry = agents.get(agentId);
    if (!entry) return false;
    const info = entry.info || {};
    const spec = info.spec || {};

    // Text match: fuzzy substring across name, project, role,
    // spec.host, spec.user. Case-insensitive.
    const q = (layoutState.filterText || '').trim().toLowerCase();
    if (q) {
        const hay = [
            info.name || agentId,
            spec.project || '',
            info.role || '',
            spec.host || '',
            spec.user || '',
            spec.agent || '',
        ].join(' ').toLowerCase();
        if (!hay.includes(q)) return false;
    }

    // Chips partitioned by category; within a category, any chip in
    // the set is a match (OR); across categories, all must match (AND).
    if (layoutState.filterChips.size > 0) {
        const byCat = new Map();
        for (const chip of layoutState.filterChips) {
            const [cat, val] = chip.split(':');
            if (!byCat.has(cat)) byCat.set(cat, new Set());

