function saveWindowUiPrefs() {
    // atn-window-ui-v1: the windowed-UI state only (layout +
    // sort + selected + per-window overrides). Omits default-state
    // windows to keep the blob small.
    try {
        const windowsOut = {};
        for (const [id, w] of Object.entries(layoutState.windows)) {
            const state = w.state || 'normal';
            const pinned = layoutState.pins.has(id);
            const pinnedRect = w.pinnedRect || null;
            // Only record windows that diverge from "normal + not pinned".
            if (state === 'normal' && !pinned) continue;
            const entry = { state };
            if (pinned) entry.pinned = true;
            if (pinnedRect) entry.pinnedRect = pinnedRect;
            windowsOut[id] = entry;
        }
        const data = JSON.stringify({
            layoutMode: layoutState.layoutMode,
            sortMode: layoutState.sortMode,
            selectedId: layoutState.selectedId,
            windows: windowsOut,
        });
        localStorage.setItem(WINDOW_PREFS_KEY, data);
    } catch (_) { /* localStorage unavailable or full — ignore */ }
}

function loadWindowUiPrefs() {
    // Read atn-window-ui-v1 and apply. Runs after loadLayoutPrefs
    // so it wins for overlapping fields (layoutMode, sortMode,
    // per-window state). Silent on malformed JSON.
    try {
        const raw = localStorage.getItem(WINDOW_PREFS_KEY);
        if (!raw) return;
        const data = JSON.parse(raw);
        if (data.layoutMode === 'tiled' || data.layoutMode === 'stack' || data.layoutMode === 'carousel') {
            layoutState.layoutMode = data.layoutMode;
        }
        if (data.sortMode === 'name' || data.sortMode === 'recent') {
            layoutState.sortMode = data.sortMode;
        }
        if (typeof data.selectedId === 'string' || data.selectedId === null) {
            layoutState.selectedId = data.selectedId;
        }
        if (data.windows && typeof data.windows === 'object') {
            for (const [id, w] of Object.entries(data.windows)) {
                const state = (w && (w.state === 'minimized' || w.state === 'maximized'))
                    ? w.state : 'normal';
                const pr = w && w.pinnedRect;
                const pinnedRect = (pr && typeof pr === 'object'
                    && typeof pr.x === 'number' && typeof pr.y === 'number'
                    && typeof pr.w === 'number' && typeof pr.h === 'number')
                    ? { x: pr.x, y: pr.y, w: pr.w, h: pr.h } : undefined;
                if (w && w.pinned === true) layoutState.pins.add(id);
                layoutState.windows[id] = {
                    state,
                    pinned: layoutState.pins.has(id),
                    ...(pinnedRect ? { pinnedRect } : {}),
                };
            }
        }
    } catch (_) { /* malformed — drop */ }
}

