function buildLayoutItems() {
    // Name-sorted, non-pinned, non-filtered agents. Coord promotion
    // is done inside computeLayout so the sort is a stable default
    // without special-casing here.
    const ids = Array.from(agents.keys())
        .filter((id) => !layoutState.pins.has(id) && matchesFilter(id));
    ids.sort((a, b) => a.localeCompare(b));
    return ids.map((id) => ({ id }));
}

input.new_string:
function buildLayoutItems() {
    // Non-pinned + filter-matching agents, sorted by `sortMode`.
    // 'name'   — stable alphabetic (default, coord-first via
    //            computeLayout's coord-promotion path).
    // 'recent' — most-recent-output first (smoothed heat desc),
    //            with name as a stable tiebreaker.
    const ids = Array.from(agents.keys())
        .filter((id) => !layoutState.pins.has(id) && matchesFilter(id));
    if (layoutState.sortMode === 'recent') {
        ids.sort((a, b) => {
            const ha = layoutState.smoothed.get(a) || 0;
            const hb = layoutState.smoothed.get(b) || 0;
            if (hb !== ha) return hb - ha;
            return a.localeCompare(b);
        });
    } else {
        ids.sort((a, b) => a.localeCompare(b));
    }
    return ids.map((id) => ({ id }));
}

