(async () => {
  const deadline = Date.now() + 4000;
  while (Date.now() < deadline) {
    if (document.querySelectorAll('.agent-panel').length >= 4) break;
    await new Promise(r => setTimeout(r, 100));
  }
  // Clean persistence for a deterministic run.
  try {
    localStorage.removeItem('atn-scale-ui-v1');
    localStorage.removeItem('atn-window-ui-v1');
  } catch(_) {}
  window.layoutState.pins = new Set();
  window.layoutState.windows = {};
  window.layoutState.selectedId = null;
  window.layoutState.layoutMode = 'tiled';
  window.layoutState.sortMode = 'name';
  if (window.updateLayoutSelector) window.updateLayoutSelector();
  if (window.updateSortSelector) window.updateSortSelector();
  window.renderSparklineRow?.();
  window.applyLayoutFresh?.();
  // Exercise: switch to stack, pin coord, switch sort to recent.
  window.setLayoutMode('stack');
  // Select coord + pin it.
  window.togglePin('coord');
  window.setSortMode('recent');
  await new Promise(r => setTimeout(r, 200));
  // Capture persisted window-ui blob.
  const raw = localStorage.getItem('atn-window-ui-v1');
  const data = raw ? JSON.parse(raw) : null;
  return { persisted: data, pinnedRects: Object.fromEntries(Object.entries(window.layoutState.windows).map(([id, w]) => [id, w.pinnedRect || null])) };
})();

