/// Drain the output channel for `window` then return everything seen
/// whose text matched any byte in the window. Used by the regression
/// tests below — they need the full buffer after the action has been
/// processed, not an early exit on the first prompt marker.
async fn drain_output(
    mut rx: tokio::sync::broadcast::Receiver<OutputSignal>,
    window: Duration,
) -> String {
    let mut collected = String::new();
    let deadline = tokio::time::Instant::now() + window;
    loop {
        let remaining = deadline.saturating_duration_since(tokio::time::Instant::now());
        if remaining.is_zero() {
            break;
        }
        match tokio::time::timeout(remaining, rx.recv()).await {
            Ok(Ok(OutputSignal::Bytes(data))) => {
                if let Ok(s) = std::str::from_utf8(&data) {
                    collected.push_str(s);
                }
            }
            Ok(Ok(_)) => {}
            Ok(Err(_)) | Err(_) => break,
        }
    }
    collected
}

