fn print_screen(screen: &vt100::Screen, trim: bool) {
    let lines = screen_to_lines(screen, trim);
    let cols = screen.size().1;
    let width = lines
        .iter()
        .map(|l| l.len())
        .max()
        .unwrap_or(0)
        .max(cols as usize);
    let border = "─".repeat(width + 2);
    println!("┌{border}┐");
    for line in &lines {
        println!("│ {line:<width$} │");
    }
    println!("└{border}┘");
}

