121	/// Shell out to curl for a single HTTP call. Returns (status_code, body).
122	/// Rust devs, avert thine eyes — reqwest would pull a mountain of deps for
123	/// a couple of lines of network glue in this one test.
124	fn curl(method: &str, url: &str, body: Option<&Value>) -> (u16, String) {
125	    let mut cmd = Command::new("curl");
126	    cmd.args([
127	        "-sS",
128	        "-o",
129	        "-",
130	        "-w",
131	        "\n__STATUS__=%{http_code}",
132	        "-X",
133	        method,
134	    ]);
135	    if let Some(b) = body {
136	        cmd.args(["-H", "Content-Type: application/json"]);
137	        cmd.args(["--data-binary", &b.to_string()]);
138	    }
139	    cmd.arg(url);
140	    let out = cmd.output().expect("curl invocation");
141	    let stdout = String::from_utf8_lossy(&out.stdout).to_string();
142	    // Parse the trailing status marker.
143	    let (body_str, status) = match stdout.rsplit_once("__STATUS__=") {
144	        Some((b, s)) => (b.trim_end_matches('\n').to_string(), s.trim()),
145	        None => (stdout, "0"),
146	    };
147	    let code = status.parse().unwrap_or(0);
148	    (code, body_str)
149	}
