162	fn poll_until<F: FnMut() -> bool>(timeout: Duration, mut f: F) -> bool {
163	    let deadline = Instant::now() + timeout;
164	    while Instant::now() < deadline {
165	        if f() {
166	            return true;
167	        }
168	        std::thread::sleep(Duration::from_millis(200));
169	    }
170	    f()
171	}
