        .unwrap_or_else(|| wiki_common::model::WikiPage::new(title, "# Requests\n\n", now));

    page.content.push_str(&format!(
        "\n## {} [{}]\n- **From:** {}\n- **Kind:** {:?}\n- **Priority:** {:?}\n- **Note:** {}\n- **ID:** {}\n",
        event.summary,
        event.timestamp,
        event.source_agent,
        event.kind,
        event.priority,
        note,
        event.id,
    ));
    page.updated_at = now;
    wiki.save_page(page).await;
}
